import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ChatMessage, QuizAttempt, Course } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Audio Helper Functions
export function encodeAudio(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decodeAudio(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const getTutorResponse = async (
  userMessage: string, 
  history: ChatMessage[],
  context: { 
    courseTitle: string; 
    lessonTitle: string; 
    lessonContent: string; 
    progress: number;
    quizHistory?: Record<string, QuizAttempt>;
  },
  imageData?: string 
) => {
  try {
    const model = 'gemini-3-pro-preview';

    let quizContext = "";
    if (context.quizHistory && Object.keys(context.quizHistory).length > 0) {
      quizContext = "\nStudent's Quiz History in this course:\n" + 
        Object.entries(context.quizHistory).map(([lessonId, attempt]) => 
          `- Lesson Completion: ${attempt.score}/${attempt.total}`
        ).join('\n');
    }

    const systemInstruction = `
      You are "Aris", a world-class AI Tutor at Edu World. 
      Context: Course "${context.courseTitle}", Lesson "${context.lessonTitle}".
      Lesson Content: "${context.lessonContent.replace(/<[^>]*>?/gm, '')}"
      Student Progress: ${context.progress}%
      ${quizContext}

      Goal: Help the student understand concepts deeply. 
      1. Use technical terms but explain them clearly.
      2. Use Markdown for formatting.
      3. ALWAYS use the googleSearch tool to provide real-world context, news, or up-to-date documentation.
      4. If an image is provided, analyze it to help answer the question.
    `;

    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [
        { text: msg.text },
        ...(msg.image ? [{ inlineData: { mimeType: 'image/jpeg', data: msg.image.split(',')[1] } }] : [])
      ]
    }));

    const currentParts: any[] = [{ text: userMessage }];
    if (imageData) {
      currentParts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: imageData.split(',')[1]
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.7,
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "I apologize, I encountered an issue processing your request.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls = groundingChunks
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      }));

    return { text, urls };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "The neural link is currently unstable. Please try your query again.", urls: [] };
  }
};

export const generateCourseOutline = async (topic: string): Promise<Partial<Course>> => {
  try {
    const model = 'gemini-3-pro-preview';
    const response = await ai.models.generateContent({
      model,
      contents: `Design a professional syllabus for a course on: ${topic}. Include 3 lessons and quizzes.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            category: { type: Type.STRING },
            instructor: { type: Type.STRING },
            price: { type: Type.NUMBER },
            lessons: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  content: { type: Type.STRING, description: "Detailed HTML content" },
                  duration: { type: Type.STRING },
                  hasAiFeature: { type: Type.BOOLEAN },
                  quiz: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        correctAnswer: { type: Type.NUMBER }
                      }
                    }
                  }
                }
              }
            },
            roadmap: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  icon: { type: Type.STRING },
                  text: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text);
    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      thumbnail: `https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&q=80&w=800&sig=${Math.random()}`,
      instructorAvatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.instructor || 'lead'}`,
      rating: 4.8,
      studentsCount: 0,
      subjects: [
        { 
          id: 's1', 
          name: 'Curriculum Core', 
          icon: 'fa-book', 
          color: 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
          subSubjects: []
        }
      ]
    };
  } catch (error) {
    console.error("Course Generation Error:", error);
    throw error;
  }
};

export const speakContent = async (text: string, voice: string = 'Kore') => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly and professionally: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voice },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    console.error("TTS Error:", error);
    return null;
  }
};

export const connectLiveTutor = (callbacks: any, systemInstruction: string) => {
  return ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks,
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
      },
      systemInstruction,
    },
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Course, Lesson, User } from '../types';
import { getTutorResponse, connectLiveTutor, decodeAudio, decodeAudioData, encodeAudio } from '../services/geminiService';

interface AIAssistantProps {
  course: Course;
  lesson: Lesson;
  user: User;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ course, lesson, user }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: `Hi! I'm your AI Tutor for Edu World's **${course.title}**. Ask me anything about "${lesson.title}" or share a screenshot of a problem you're stuck on!`, 
      timestamp: new Date() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isVoiceMode, setIsVoiceMode] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Live Voice Refs
  const sessionRef = useRef<any>(null);
  const audioContextsRef = useRef<{ input: AudioContext; output: AudioContext } | null>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  useEffect(() => {
    return () => {
      stopVoiceMode();
    };
  }, []);

  const stopVoiceMode = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (audioContextsRef.current) {
      audioContextsRef.current.input.close();
      audioContextsRef.current.output.close();
      audioContextsRef.current = null;
    }
    setIsVoiceMode(false);
  };

  const startVoiceMode = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const outputNode = outputCtx.createGain();
      outputNode.connect(outputCtx.destination);

      audioContextsRef.current = { input: inputCtx, output: outputCtx };
      setIsVoiceMode(true);

      const sysMsg = `You are Aris, an AI Tutor for the course ${course.title}. Currently teaching lesson ${lesson.title}. Lesson content: ${lesson.content.replace(/<[^>]*>?/gm, '')}. Help the student with spoken explanations.`;

      const sessionPromise = connectLiveTutor({
        onopen: () => {
          const source = inputCtx.createMediaStreamSource(stream);
          const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const l = inputData.length;
            const int16 = new Int16Array(l);
            for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;

            const pcmBlob = {
              data: encodeAudio(new Uint8Array(int16.buffer)),
              mimeType: 'audio/pcm;rate=16000',
            };

            sessionPromise.then(session => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(inputCtx.destination);
        },
        onmessage: async (message: any) => {
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData.data;
          if (base64Audio) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
            const audioBuffer = await decodeAudioData(decodeAudio(base64Audio), outputCtx, 24000, 1);
            const source = outputCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outputNode);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            audioSourcesRef.current.add(source);
            source.onended = () => audioSourcesRef.current.delete(source);
          }

          if (message.serverContent?.interrupted) {
            audioSourcesRef.current.forEach(s => s.stop());
            audioSourcesRef.current.clear();
            nextStartTimeRef.current = 0;
          }
        },
        onerror: (e: any) => {
          console.error("Live Tutor Error:", e);
          stopVoiceMode();
        },
        onclose: () => {
          setIsVoiceMode(false);
        }
      }, sysMsg);

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice mode:", err);
      stopVoiceMode();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || isTyping) return;

    const currentImage = selectedImage;
    const userMsg: ChatMessage = { 
      role: 'user', 
      text: input, 
      timestamp: new Date(),
      image: currentImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setSelectedImage(null);
    setIsTyping(true);

    const result = await getTutorResponse(
      input, 
      messages, 
      {
        courseTitle: course.title,
        lessonTitle: lesson.title,
        lessonContent: lesson.content,
        progress: course.progress || 0,
        quizHistory: user.quizScores
      },
      currentImage || undefined
    );

    const botMsg: ChatMessage = { 
      role: 'model', 
      text: result.text, 
      timestamp: new Date(),
      groundingUrls: result.urls 
    };
    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  const formatTimestamp = (date: any) => {
    if (!date) return "";
    const d = new Date(date);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden shadow-sm">
      <div className="bg-indigo-600 p-4 text-white flex items-center justify-between shadow-lg relative z-10">
        <div className="flex items-center space-x-3">
          <div className="w-9 h-9 bg-white/10 backdrop-blur-md rounded-xl flex items-center justify-center border border-white/20 shadow-inner">
            <i className="fas fa-robot text-lg"></i>
          </div>
          <div>
            <h4 className="font-black text-sm tracking-tight">Personal AI Tutor</h4>
            <div className="flex items-center space-x-2">
              <span className={`w-1.5 h-1.5 ${isVoiceMode ? 'bg-rose-400 animate-ping' : 'bg-green-400 animate-pulse'} rounded-full`}></span>
              <p className="text-[10px] text-indigo-100 font-bold uppercase tracking-widest opacity-80">
                {isVoiceMode ? 'Voice Mode Active' : 'Search Grounding Enabled'}
              </p>
            </div>
          </div>
        </div>
        <button 
          onClick={isVoiceMode ? stopVoiceMode : startVoiceMode}
          className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isVoiceMode ? 'bg-rose-500 shadow-rose-500/30' : 'bg-white/10 hover:bg-white/20'} border border-white/10`}
          title={isVoiceMode ? "Stop Voice Mode" : "Start Voice Tutoring"}
        >
          <i className={`fas ${isVoiceMode ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-950/50">
        {isVoiceMode && (
          <div className="flex flex-col items-center justify-center py-12 text-center">
             <div className="flex items-center space-x-2 mb-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="w-1 bg-indigo-500 rounded-full animate-pulse" style={{ height: `${Math.random() * 2 + 1}rem`, animationDelay: `${i * 0.1}s` }}></div>
                ))}
             </div>
             <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Aris is listening...</p>
          </div>
        )}

        {!isVoiceMode && messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-900 text-slate-100 border border-slate-800 rounded-tl-none'
            }`}>
              {msg.image && (
                <div className="mb-2 rounded-lg overflow-hidden border border-black/20">
                  <img src={msg.image} className="max-w-full h-auto" alt="shared content" />
                </div>
              )}
              <div className={`prose prose-sm max-w-none ${msg.role === 'user' ? 'prose-invert text-white' : 'prose-invert text-slate-100'}`}>
                {msg.text.split('\n').map((line, idx) => (
                  <p key={idx}>{line}</p>
                ))}
              </div>

              {msg.groundingUrls && msg.groundingUrls.length > 0 && (
                <div className="mt-4 pt-3 border-t border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Sources:</p>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingUrls.map((link, idx) => (
                      <a 
                        key={idx} 
                        href={link.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center px-2 py-1 bg-slate-950 rounded-lg text-[10px] text-indigo-400 hover:text-white hover:bg-indigo-600 transition-all border border-slate-800"
                      >
                        <i className="fas fa-link mr-1.5 text-[8px]"></i>
                        <span className="truncate max-w-[150px]">{link.title}</span>
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <span className={`text-[10px] mt-1 block font-black uppercase tracking-widest ${msg.role === 'user' ? 'text-indigo-200 text-right' : 'text-slate-500'}`}>
                {formatTimestamp(msg.timestamp)}
              </span>
            </div>
          </div>
        ))}
        {isTyping && !isVoiceMode && (
          <div className="flex justify-start">
            <div className="bg-slate-900 border border-slate-800 rounded-2xl px-5 py-4 flex space-x-1.5 shadow-sm">
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 border-t border-slate-800">
        {selectedImage && (
          <div className="mb-3 relative inline-block group animate-in slide-in-from-bottom-2">
            <img src={selectedImage} className="h-20 w-20 object-cover rounded-xl border-2 border-indigo-600 shadow-lg" alt="preview" />
            <button 
              onClick={() => setSelectedImage(null)}
              className="absolute -top-2 -right-2 bg-slate-950 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-lg border border-slate-800"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>
        )}
        <div className="flex items-center space-x-2 bg-slate-950 rounded-2xl px-4 py-2 border border-slate-800 focus-within:border-indigo-500/50 transition-all">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="text-slate-500 hover:text-indigo-400 transition-colors p-1"
          >
            <i className="fas fa-image"></i>
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isVoiceMode ? "Voice mode active..." : "Type your question..."}
            disabled={isVoiceMode}
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm py-2 text-slate-100 font-medium placeholder:text-slate-600 disabled:opacity-50"
          />
          <button 
            onClick={handleSend}
            disabled={(!input.trim() && !selectedImage) || isTyping || isVoiceMode}
            className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${
              (input.trim() || selectedImage) && !isTyping && !isVoiceMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-700'
            }`}
          >
            <i className="fas fa-paper-plane-top"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);

  // Quiz State
  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  // Video Player States
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Handle lesson change
  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    // Reset video state
    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  // Video Source Management
  const videoSrc = useMemo(() => {
    if (!activeLesson.videoUrl) return '';
    return activeLesson.videoUrl;
  }, [activeLesson.videoUrl]);

  // Video Controls
  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className="flex h-screen bg-[#020617] overflow-hidden">
      {/* Lessons Navigation Sidebar */}
      <div className="w-80 border-r border-slate-800 flex flex-col bg-slate-950/50 backdrop-blur-3xl">
        <div className="p-8 border-b border-slate-800">
           <button onClick={onBack} className="flex items-center text-slate-500 hover:text-white mb-6 text-[10px] font-black uppercase tracking-widest transition-all">
             <i className="fas fa-arrow-left mr-3"></i> Dashboard
           </button>
           <h2 className="text-sm font-black text-white uppercase tracking-wider line-clamp-2 leading-tight">{course.title}</h2>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-2 no-scrollbar">
          {course.lessons.map((lesson, idx) => (
            <button
              key={lesson.id}
              onClick={() => setActiveLessonId(lesson.id)}
              className={`w-full text-left p-4 rounded-[20px] transition-all border ${
                activeLessonId === lesson.id 
                  ? 'bg-indigo-600/10 border-indigo-500/30 text-white shadow-lg' 
                  : 'border-transparent text-slate-500 hover:bg-slate-900/50 hover:text-slate-300'
              }`}
            >
              <div className="flex items-center space-x-4">
                <span className="text-[10px] font-black opacity-30">{String(idx + 1).padStart(2, '0')}</span>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-bold truncate">{lesson.title}</p>
                  <p className="text-[9px] uppercase tracking-widest font-black opacity-40 mt-1">{lesson.duration}</p>
                </div>
                {user.quizScores[lesson.id] && <i className="fas fa-check-circle text-emerald-500 text-xs"></i>}
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className="bg-black aspect-video relative group flex items-center justify-center overflow-hidden">
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[2px] cursor-pointer">
                    <div className="w-24 h-24 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-3xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95">
                      <i className="fas fa-play ml-1"></i>
                    </div>
                  </div>
                )}
                <div className={`absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-black/90 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0 pointer-events-none'}`}>
                  <div className="relative group/progress mb-6">
                    <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                    <div className="absolute top-0 left-0 h-1 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                  </div>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-8 text-white">
                      <button onClick={togglePlay} className="text-xl hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                      <div className="flex items-center space-x-4 group/volume">
                        <button onClick={toggleMute} className="text-xl hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-24 transition-all duration-300 h-1 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[11px] font-black tracking-[0.2em] opacity-60">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-2 opacity-30">/</span> {formatTime(duration)}</span>
                    </div>
                    <button onClick={toggleFullscreen} className="text-white text-xl hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </>
            ) : (
              <div className="text-slate-800 flex flex-col items-center">
                <div className="w-20 h-20 rounded-full bg-slate-900 flex items-center justify-center mb-6 border border-slate-800">
                  <i className="fas fa-video-slash text-2xl opacity-20"></i>
                </div>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-30">No Stream Found</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto p-12 md:p-20">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
               <div className="flex space-x-8 border-b border-slate-800/50 pb-2">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notebook', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-4 text-[10px] font-black uppercase tracking-[0.3em] transition-all border-b-2 flex items-center space-x-3 ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-xs`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all border ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-2`}></i> {isReading ? 'Reading Aloud...' : 'Listen to Theory'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <h1 className="text-4xl font-black mb-10 tracking-tight leading-tight">{activeLesson.title}</h1>
                  <div className="text-slate-400 leading-relaxed text-lg ql-editor" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-20 pt-10 border-t border-slate-800">
                       <h3 className="text-sm font-black text-slate-500 uppercase tracking-[0.3em] mb-8">Asset Library</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-4 bg-slate-900/50 border border-slate-800 rounded-2xl hover:border-indigo-500/50 transition-all group">
                               <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-indigo-400 mr-4 shadow-sm group-hover:bg-indigo-600 group-hover:text-white transition-all"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'}`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-xs font-bold text-white truncate">{res.title}</p>
                                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-12">
                  <div className="flex items-center justify-between">
                    <div>
                      <h2 className="text-2xl font-black text-white">Neural Assessment</h2>
                      <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.2em] mt-2">Validate your concept retention</p>
                    </div>
                  </div>

                  {quizState.complete ? (
                    <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-16 text-center shadow-2xl">
                      <div className="w-24 h-24 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-10 text-4xl border border-indigo-500/20 shadow-inner"><i className="fas fa-award"></i></div>
                      <h3 className="text-3xl font-black text-white mb-4">Assessment Finalized</h3>
                      <p className="text-slate-500 text-xs font-black uppercase tracking-widest mb-10">Neural Efficiency: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-12 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Initiate Retake</button>
                    </div>
                  ) : (
                    <div className="space-y-12">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/50 border border-slate-800 rounded-[32px] p-10 shadow-lg">
                          <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-6">Subject Query {qIdx + 1}</p>
                          <p className="text-xl font-bold text-slate-100 mb-10 leading-snug">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-6 rounded-[24px] text-left text-sm font-bold transition-all border flex items-center space-x-4 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl translate-y-[-2px]' : 'bg-slate-950/50 border-slate-800 text-slate-500 hover:border-slate-600'}`}>
                                <span className={`w-8 h-8 rounded-xl flex items-center justify-center text-[10px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/20' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xs uppercase tracking-[0.4em] shadow-2xl">Commit Responses</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-10">
                  <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-black text-white">Notebook</h2>
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest bg-slate-900 px-4 py-1.5 rounded-full border border-slate-800">Auto-syncing Enabled</span>
                  </div>
                  <textarea value={user.notes?.[activeLesson.id] || ''} onChange={(e) => onNotesUpdate(activeLesson.id, e.target.value)} placeholder="Capture your insights from this lecture..." className="w-full h-[500px] bg-slate-950 border border-slate-800 rounded-[40px] p-12 text-slate-300 font-medium placeholder:text-slate-800 focus:ring-0 focus:border-indigo-600/50 transition-all shadow-inner leading-relaxed text-lg" />
                </div>
              )}
            </div>
          </div>
        </div>

        <button onClick={() => setIsAiOpen(!isAiOpen)} className={`fixed bottom-10 right-10 w-20 h-20 rounded-[30px] flex items-center justify-center transition-all shadow-2xl z-[100] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-110 active:scale-95'}`}>
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-2xl`}></i>
          {!isAiOpen && <span className="absolute right-full mr-6 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Consult Tutor</span>}
        </button>
        <div className={`fixed inset-y-0 right-0 w-full md:w-[450px] bg-slate-950 border-l border-slate-800 z-[90] transition-transform duration-700 ease-in-out shadow-2xl ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, RoadmapItem, Resource } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [uploadingResourceIdx, setUploadingResourceIdx] = useState<number | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const quillRef = useRef<HTMLDivElement>(null);
  const quillInstance = useRef<any>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  // Handle Quill Initialization
  useEffect(() => {
    if (editingLessonIdx !== null && quillRef.current && !quillInstance.current) {
      const Quill = (window as any).Quill;
      if (Quill) {
        // Clear container before init to prevent mounting errors
        if (quillRef.current) quillRef.current.innerHTML = '';

        quillInstance.current = new Quill(quillRef.current, {
          theme: 'snow',
          modules: {
            toolbar: [
              [{ 'header': [1, 2, 3, false] }],
              ['bold', 'italic', 'underline', 'strike'],
              [{ 'color': [] }, { 'background': [] }],
              [{ 'script': 'sub'}, { 'script': 'super' }],
              [{ 'list': 'ordered'}, { 'list': 'bullet' }],
              [{ 'indent': '-1'}, { 'indent': '+1' }],
              [{ 'align': [] }],
              ['formula'],
              ['link', 'blockquote', 'code-block'],
              ['clean']
            ]
          }
        });

        const initialContent = currentCourse?.lessons?.[editingLessonIdx]?.content || '';
        quillInstance.current.root.innerHTML = initialContent;

        const handleUpdate = () => {
          const html = quillInstance.current.root.innerHTML;
          updateLesson(editingLessonIdx, { content: html });
        };

        quillInstance.current.on('text-change', handleUpdate);

        return () => {
          if (quillInstance.current) {
            quillInstance.current.off('text-change', handleUpdate);
            quillInstance.current = null;
          }
        };
      }
    }
  }, [editingLessonIdx]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || uploadingResourceIdx === null) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      updateResource(uploadingResourceIdx, { url: event.target?.result as string });
      setIsUploading(false);
      setUploadingResourceIdx(null);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
