                                  <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-800 hover:text-rose-500 p-1 transition-colors"><i className="fas fa-times text-[10px]"></i></button>
                                </div>
                              ))}
                              {(ss.units || []).length === 0 && (
                                <p className="text-[9px] font-black text-slate-700 uppercase tracking-widest pl-4 italic">No mapped units yet</p>
                              )}
                            </div>
                          </div>
                        ))}
                        {(subj.subSubjects || []).length === 0 && (
                          <div className="py-6 flex flex-col items-center justify-center opacity-40">
                             <i className="fas fa-sitemap text-2xl mb-2 text-slate-700"></i>
                             <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Structure Pending Establishment</p>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                  {(currentCourse.subjects || []).length === 0 && (
                    <div className="py-24 text-center border-2 border-dashed border-slate-800 rounded-[40px] opacity-20">
                       <i className="fas fa-cubes text-4xl mb-4 text-slate-700"></i>
                       <p className="text-[10px] font-black uppercase tracking-widest">Architectural framework pending initialization</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
        <div>
          <h1 className="text-3xl md:text-5xl font-black text-white tracking-tight leading-none mb-2">Academic Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Manage neural-linked expert programs</p>
        </div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl shadow-indigo-600/20 tracking-widest active:scale-95 transition-all"><i className="fas fa-plus mr-3"></i> Initialize Program</button>
      </div>

