          </div>

          <div className="absolute -bottom-24 -left-24 w-96 h-96 bg-indigo-600/10 rounded-full blur-[120px] pointer-events-none group-hover:bg-indigo-600/15 transition-all duration-1000"></div>
          <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/5 rounded-full blur-[100px] pointer-events-none"></div>
        </div>
      </div>

      {/* Content Navigator */}
      <div className="px-4 md:px-0 pb-12">
        <div className="bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-4 md:p-10 shadow-2xl backdrop-blur-sm min-h-[400px]">
