              <div className="flex items-center justify-between">
                <h3 className="text-sm font-black text-white uppercase tracking-[0.2em] flex items-center">
                  <i className="fas fa-sitemap mr-4 text-indigo-500"></i> Subject Explorer
                </h3>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5 md:gap-8">
                {(activeCourse.subjects || []).map((subj) => (
                  <button 
                    key={subj.id} 
                    onClick={() => handleSubjectClick(subj)}
                    className="flex flex-col p-8 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-xl active:scale-95 text-left h-full"
                  >
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-110 transition-transform mb-6`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
