                          <div className="space-y-2 animate-in slide-in-from-top-2">
                            <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Exam Duration (Mins)</label>
                            <input 
                              type="number" 
                              value={currentLesson.examDuration || 30} 
                              onChange={e => updateLesson(editingLessonIdx!, { examDuration: parseInt(e.target.value) })}
                              className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold text-xs outline-none focus:border-rose-500" 
                            />
                          </div>
