                    key={subj.id} 
                    onClick={() => handleSubjectClick(subj)}
                    className="flex flex-col p-8 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-xl active:scale-95 text-left h-full"
                  >
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-110 transition-transform mb-6`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div className="space-y-2 flex-1">
                      <h4 className="text-xl font-black text-slate-100 group-hover:text-white transition-colors tracking-tight">{subj.name}</h4>
                      <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em]">{subj.subSubjects.length} Specialized Paths</p>
                    </div>
                    <div className="mt-8 pt-6 border-t border-slate-800/50 flex items-center justify-between text-[10px] font-black uppercase tracking-widest text-slate-500 group-hover:text-indigo-400 transition-colors">
                      <span>Enter Module</span>
                      <i className="fas fa-arrow-right-long group-hover:translate-x-2 transition-transform"></i>
