              {filteredLessons.length > 0 && (
                <div className="space-y-8 pt-10 border-t border-slate-800/50">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">General Resources</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {filteredLessons.map((lesson) => (
                      <button 
                        key={lesson.id} 
                        onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                        className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                      >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center mr-5 transition-colors ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-700 group-hover:text-indigo-400 shadow-inner'}`}>
                          <i className={`fas ${lesson.isExamMode ? 'fa-file-signature' : 'fa-file-lines'}`}></i>
                        </div>
                        <div className="flex-1 text-left text-sm font-bold text-slate-100 group-hover:text-white transition-colors">
                          {lesson.title}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* SubSubject Level Cards */}
          {selectedSubject && !selectedSubSubject && (
            <div className="space-y-10 animate-in slide-in-from-right-8 duration-500">
               <div className="flex items-center space-x-4 mb-6">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center border ${selectedSubject.color}`}><i className={`fas ${selectedSubject.icon}`}></i></div>
                <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">{selectedSubject.name} Pathways</h3>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {selectedSubject.subSubjects.map((ss) => (
                  <button 
                    key={ss.id} 
                    onClick={() => handleSubSubjectClick(ss)}
                    className="flex flex-col p-7 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-xl active:scale-95 text-left"
                  >
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner mb-5`}><i className="fas fa-folder-tree"></i></div>
                    <span className="text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
                    <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-2">{ss.units.length} Units Available</p>
                  </button>
                ))}
