                  <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">{selectedSubSubject.name} Curriculum</h3>
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {selectedSubSubject.units?.map((unit) => {
                  const hasExam = activeCourse.lessons.some(l => l.unitId === unit.id && l.isExamMode);
                  const lessonCount = activeCourse.lessons.filter(l => l.unitId === unit.id).length;
                  return (
                    <button 
                      key={unit.id} 
                      onClick={() => handleUnitClick(unit)}
                      className={`flex flex-col p-7 bg-slate-950 border rounded-[32px] transition-all group shadow-xl active:scale-95 text-left h-full ${hasExam ? 'border-rose-500/30 hover:border-rose-500/50' : 'border-slate-800/50 hover:border-emerald-500/40'} hover:bg-slate-900`}
                    >
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 border border-slate-800 group-hover:text-white transition-all shadow-inner mb-5 ${hasExam ? 'text-rose-400 group-hover:bg-rose-600' : 'text-emerald-400 group-hover:bg-emerald-600'}`}>
                        <i className={`fas ${hasExam ? 'fa-file-signature' : 'fa-box-open'}`}></i>
                      </div>
                      <span className="text-lg font-black text-slate-100 group-hover:text-white transition-colors leading-tight mb-2">{unit.name}</span>
                      <div className="flex items-center justify-between mt-auto">
                        <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest">{lessonCount} Modules</span>
                        {hasExam && <span className="text-[7px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/5 px-2 py-0.5 rounded border border-rose-500/10">EXAM ACTIVE</span>}
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {/* Lesson List */}
          {selectedUnit && (
            <div className="space-y-8 animate-in slide-in-from-right-8 duration-500">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-12 h-12 rounded-2xl bg-slate-900 text-indigo-400 border border-slate-800 flex items-center justify-center text-xl shadow-inner"><i className="fas fa-file-invoice"></i></div>
                  <div>
                    <h3 className="text-lg font-black text-white tracking-tight">{selectedUnit.name} Modules</h3>
                  </div>
                </div>
                <div className="flex items-center bg-slate-950 px-4 py-2.5 rounded-2xl border border-slate-800 w-full md:w-64">
                   <i className="fas fa-magnifying-glass text-slate-700 mr-3 text-xs"></i>
                   <input type="text" value={lessonSearch} onChange={(e) => setLessonSearch(e.target.value)} placeholder="Filter unit..." className="w-full bg-transparent border-none focus:ring-0 text-xs text-slate-300 font-bold placeholder:text-slate-800" />
                </div>
              </div>

              {filteredLessons.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  {filteredLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md text-left"
                    >
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xs font-black border mr-6 transition-all shadow-inner ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-900 text-slate-500 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                        {lesson.isExamMode ? <i className="fas fa-file-signature"></i> : <i className="fas fa-book-open text-[10px]"></i>}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center space-x-2">
                          <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-base leading-tight truncate">{lesson.title}</h4>
                          {lesson.isExamMode && <span className="text-[7px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1.5 py-0.5 rounded border border-rose-500/20">EXAM</span>}
                        </div>
                        <div className="flex items-center space-x-3 mt-1.5 overflow-hidden">
                          {lesson.hasAiFeature && !lesson.isExamMode && <div className="flex items-center space-x-1 px-1.5 py-0.5 bg-indigo-500/10 text-indigo-400 rounded-md border border-indigo-500/20 shrink-0"><i className="fas fa-sparkles text-[7px]"></i><span className="text-[7px] font-black uppercase tracking-widest">AI ACTIVE</span></div>}
                        </div>
                      </div>
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500 shadow-rose-500/20' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white group-hover:shadow-indigo-600/20'}`}>
                        <i className="fas fa-play text-[9px] ml-0.5"></i>
                      </div>
                    </button>
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 opacity-30 text-center px-6">
                  <i className="fas fa-box-open text-4xl mb-4 text-slate-700"></i>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">No matching modules found in this registry</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, RoadmapItem, Resource } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [uploadingResourceIdx, setUploadingResourceIdx] = useState<number | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const quillRef = useRef<HTMLDivElement>(null);
  const quillInstance = useRef<any>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  // Handle Quill Initialization
  useEffect(() => {
    if (editingLessonIdx !== null && quillRef.current && !quillInstance.current) {
      const Quill = (window as any).Quill;
      if (Quill) {
        // Clear container before init to prevent mounting errors
        if (quillRef.current) quillRef.current.innerHTML = '';

        quillInstance.current = new Quill(quillRef.current, {
          theme: 'snow',
          modules: {
            toolbar: [
              [{ 'header': [1, 2, 3, false] }],
              ['bold', 'italic', 'underline', 'strike'],
              [{ 'color': [] }, { 'background': [] }],
              [{ 'script': 'sub'}, { 'script': 'super' }],
              [{ 'list': 'ordered'}, { 'list': 'bullet' }],
              [{ 'indent': '-1'}, { 'indent': '+1' }],
              [{ 'align': [] }],
              ['formula'],
              ['link', 'blockquote', 'code-block'],
              ['clean']
            ]
          }
        });

        const initialContent = currentCourse?.lessons?.[editingLessonIdx]?.content || '';
        quillInstance.current.root.innerHTML = initialContent;

        const handleUpdate = () => {
          const html = quillInstance.current.root.innerHTML;
          updateLesson(editingLessonIdx, { content: html });
        };

        quillInstance.current.on('text-change', handleUpdate);

        return () => {
          if (quillInstance.current) {
            quillInstance.current.off('text-change', handleUpdate);
            quillInstance.current = null;
          }
        };
      }
    }
  }, [editingLessonIdx]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || uploadingResourceIdx === null) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      updateResource(uploadingResourceIdx, { url: event.target?.result as string });
      setIsUploading(false);
      setUploadingResourceIdx(null);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link',
        description: ''
      };

      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };

      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);

      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[3], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
