export default AdminPanel;

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);

  // Quiz State
  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  // Video Player States
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Handle lesson change
  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    // Reset video state
    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  // Video Source Management
  const videoSrc = useMemo(() => {
    if (!activeLesson.videoUrl) return '';
    return activeLesson.videoUrl;
  }, [activeLesson.videoUrl]);

  // Video Controls
  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className="flex flex-col h-screen bg-[#020617] overflow-hidden">
      {/* Top Header Section - Replaces Sidebar Header */}
      <header className="px-6 md:px-12 py-6 border-b border-slate-800 bg-slate-950/50 backdrop-blur-xl flex flex-col md:flex-row md:items-center justify-between gap-4 shrink-0">
        <div className="flex items-center space-x-6">
          <button 
            onClick={onBack} 
            className="group flex items-center space-x-3 text-slate-500 hover:text-white transition-all"
          >
            <div className="w-10 h-10 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all">
              <i className="fas fa-arrow-left text-xs"></i>
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em]">Registry Hub</span>
          </button>
          <div className="h-8 w-px bg-slate-800 hidden md:block"></div>
          <h2 className="text-sm md:text-base font-black text-white uppercase tracking-wider line-clamp-1">{course.title}</h2>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 text-[9px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-500/10 px-3 py-1.5 rounded-full border border-indigo-500/20">
            <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-pulse"></span>
            <span>Module: {activeLesson.title}</span>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className="bg-black aspect-video relative group flex items-center justify-center overflow-hidden">
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[2px] cursor-pointer">
                    <div className="w-24 h-24 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-3xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95">
                      <i className="fas fa-play ml-1"></i>
                    </div>
                  </div>
                )}
                <div className={`absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-black/90 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0 pointer-events-none'}`}>
                  <div className="relative group/progress mb-6">
                    <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                    <div className="absolute top-0 left-0 h-1 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                  </div>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-8 text-white">
                      <button onClick={togglePlay} className="text-xl hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                      <div className="flex items-center space-x-4 group/volume">
                        <button onClick={toggleMute} className="text-xl hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-24 transition-all duration-300 h-1 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[11px] font-black tracking-[0.2em] opacity-60">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-2 opacity-30">/</span> {formatTime(duration)}</span>
                    </div>
                    <button onClick={toggleFullscreen} className="text-white text-xl hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </>
            ) : (
              <div className="text-slate-800 flex flex-col items-center">
                <div className="w-20 h-20 rounded-full bg-slate-900 flex items-center justify-center mb-6 border border-slate-800">
                  <i className="fas fa-video-slash text-2xl opacity-20"></i>
                </div>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-30">No Stream Found</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto p-8 md:p-20">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
               <div className="flex space-x-8 border-b border-slate-800/50 pb-2 overflow-x-auto no-scrollbar">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notebook', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-4 text-[10px] font-black uppercase tracking-[0.3em] transition-all border-b-2 flex items-center space-x-3 whitespace-nowrap ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-xs`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all border ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-2`}></i> {isReading ? 'Reading Aloud...' : 'Listen to Theory'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <h1 className="text-3xl md:text-5xl font-black mb-10 tracking-tight leading-tight">{activeLesson.title}</h1>
                  <div className="text-slate-400 leading-relaxed text-lg ql-editor" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-20 pt-10 border-t border-slate-800">
                       <h3 className="text-sm font-black text-slate-500 uppercase tracking-[0.3em] mb-8">Asset Library</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-4 bg-slate-900/50 border border-slate-800 rounded-2xl hover:border-indigo-500/50 transition-all group">
                               <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-indigo-400 mr-4 shadow-sm group-hover:bg-indigo-600 group-hover:text-white transition-all"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'}`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-xs font-bold text-white truncate">{res.title}</p>
                                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-12">
                  <div className="flex items-center justify-between">
                    <div>
                      <h2 className="text-2xl font-black text-white">Neural Assessment</h2>
                      <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.2em] mt-2">Validate your concept retention</p>
                    </div>
                  </div>

                  {quizState.complete ? (
                    <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-16 text-center shadow-2xl">
                      <div className="w-24 h-24 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-10 text-4xl border border-indigo-500/20 shadow-inner"><i className="fas fa-award"></i></div>
                      <h3 className="text-3xl font-black text-white mb-4">Assessment Finalized</h3>
                      <p className="text-slate-500 text-xs font-black uppercase tracking-widest mb-10">Neural Efficiency: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-12 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Initiate Retake</button>
                    </div>
                  ) : (
                    <div className="space-y-12">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/50 border border-slate-800 rounded-[32px] p-10 shadow-lg">
                          <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-6">Subject Query {qIdx + 1}</p>
                          <p className="text-xl font-bold text-slate-100 mb-10 leading-snug">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-6 rounded-[24px] text-left text-sm font-bold transition-all border flex items-center space-x-4 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl translate-y-[-2px]' : 'bg-slate-950/50 border-slate-800 text-slate-500 hover:border-slate-600'}`}>
                                <span className={`w-8 h-8 rounded-xl flex items-center justify-center text-[10px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/20' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xs uppercase tracking-[0.4em] shadow-2xl">Commit Responses</button>}
                    </div>
                  )}
