                      </div>
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500 shadow-rose-500/20' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white group-hover:shadow-indigo-600/20'}`}>
