import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);

  // Quiz State
  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  // Video Player States
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Handle lesson change
  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    // Reset video state
    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  // Video Source Management
  const videoSrc = useMemo(() => {
    if (!activeLesson.videoUrl) return '';
    return activeLesson.videoUrl;
  }, [activeLesson.videoUrl]);

  // Video Controls
  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className="flex flex-col h-screen bg-[#020617] overflow-hidden">
      {/* Small Header */}
      <header className="px-6 md:px-10 py-3 border-b border-slate-800 bg-slate-950/80 backdrop-blur-xl flex items-center justify-between shrink-0 z-50">
        <button 
          onClick={onBack} 
          className="group flex items-center space-x-2 text-slate-500 hover:text-white transition-all"
        >
          <div className="w-7 h-7 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all">
            <i className="fas fa-arrow-left text-[9px]"></i>
          </div>
          <span className="text-[8px] font-black uppercase tracking-[0.2em]">Close</span>
        </button>

        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 text-[8px] font-black text-indigo-400/70 uppercase tracking-widest px-2.5 py-1 rounded-full border border-indigo-500/10">
            <span className="w-1 h-1 bg-indigo-500/50 rounded-full animate-pulse"></span>
            <span>Focus Mode</span>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className="bg-black aspect-video relative group flex items-center justify-center overflow-hidden max-h-[70vh]">
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[1px] cursor-pointer">
                    <div className="w-16 h-16 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95">
                      <i className="fas fa-play ml-0.5"></i>
                    </div>
                  </div>
                )}
                <div className={`absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/90 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-2 opacity-0 pointer-events-none'}`}>
                  <div className="relative group/progress mb-3">
                    <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-0.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                    <div className="absolute top-0 left-0 h-0.5 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                  </div>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-5 text-white">
                      <button onClick={togglePlay} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                      <div className="flex items-center space-x-3 group/volume">
                        <button onClick={toggleMute} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-16 transition-all duration-300 h-0.5 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[9px] font-black tracking-[0.2em] opacity-40">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-1.5">/</span> {formatTime(duration)}</span>
                    </div>
                    <button onClick={toggleFullscreen} className="text-white text-base hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </>
            ) : (
              <div className="text-slate-800 flex flex-col items-center">
                <div className="w-12 h-12 rounded-full bg-slate-900 flex items-center justify-center mb-4 border border-slate-800">
                  <i className="fas fa-video-slash text-base opacity-20"></i>
                </div>
                <p className="text-[8px] font-black uppercase tracking-[0.3em] opacity-30">Academic Feed</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto p-4 md:p-10">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 border-b border-slate-800/40">
               <div className="flex space-x-6 overflow-x-auto no-scrollbar pb-px">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notes', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-3 text-[8px] font-black uppercase tracking-[0.3em] transition-all border-b-2 flex items-center space-x-2 whitespace-nowrap ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-[10px]`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`mb-3 md:mb-0 px-3 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all border ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-1.5`}></i> {isReading ? 'Audio Link...' : 'TTS'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <div className="text-slate-400 leading-relaxed text-base ql-editor px-0" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-12 pt-8 border-t border-slate-800/60">
                       <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] mb-6">Module Assets</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-3 bg-slate-900/30 border border-slate-800/60 rounded-xl hover:border-indigo-500/30 transition-all group">
                               <div className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-indigo-400/60 mr-3 shadow-sm group-hover:bg-indigo-600 group-hover:text-white transition-all"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'} text-xs`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-[10px] font-bold text-slate-300 truncate leading-tight">{res.title}</p>
                                  <p className="text-[7px] font-black text-slate-600 uppercase tracking-widest mt-0.5">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-8">
                  <div>
                    <h2 className="text-lg font-black text-white uppercase tracking-tight">Assessment</h2>
                    <p className="text-slate-700 text-[7px] font-black uppercase tracking-[0.2em] mt-1">Neural Verification Chain</p>
                  </div>

                  {quizState.complete ? (
                    <div className="bg-slate-900/50 border border-slate-800 rounded-3xl p-10 text-center shadow-xl">
                      <div className="w-16 h-16 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl border border-indigo-500/20 shadow-inner"><i className="fas fa-star-half-stroke"></i></div>
                      <h3 className="text-xl font-black text-white mb-2 uppercase">Complete</h3>
                      <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mb-8">Score: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all">Retry</button>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/30 border border-slate-800/40 rounded-2xl p-6 shadow-sm">
                          <p className="text-[7px] font-black text-slate-700 uppercase tracking-widest mb-4">Query 0{qIdx + 1}</p>
                          <p className="text-base font-bold text-slate-100 mb-6 leading-tight">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-4 rounded-xl text-left text-[11px] font-bold transition-all border flex items-center space-x-3 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600/20 border-indigo-500/50 text-white translate-y-[-0.5px]' : 'bg-slate-950/20 border-slate-800/40 text-slate-500 hover:border-slate-700'}`}>
                                <span className={`w-6 h-6 rounded-md flex items-center justify-center text-[8px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/10' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[9px] uppercase tracking-[0.3em] shadow-lg">Finalize Response</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h2 className="text-lg font-black text-white uppercase tracking-tight">Log</h2>
                    <span className="text-[7px] font-black text-slate-700 uppercase tracking-widest bg-slate-900/30 px-2.5 py-1 rounded-full border border-slate-800">Auto-Save</span>
                  </div>
                  <textarea value={user.notes?.[activeLesson.id] || ''} onChange={(e) => onNotesUpdate(activeLesson.id, e.target.value)} placeholder="Neural log: Record insights..." className="w-full h-[350px] bg-slate-950 border border-slate-800 rounded-2xl p-6 text-slate-300 font-medium placeholder:text-slate-800 focus:ring-0 focus:border-indigo-600/20 transition-all shadow-inner leading-relaxed text-sm" />
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Small AI FAB */}
        <button onClick={() => setIsAiOpen(!isAiOpen)} className={`fixed bottom-6 right-6 w-12 h-12 rounded-xl flex items-center justify-center transition-all shadow-xl z-[100] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-105 active:scale-95'}`}>
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-base`}></i>
        </button>

        <div className={`fixed inset-y-0 right-0 w-full md:w-[380px] bg-slate-950 border-l border-slate-800 z-[90] transition-transform duration-500 ease-out shadow-2xl ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);

  // Quiz State
  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  // Video Player States
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  // Notebook Editor Ref
  const quillRef = useRef<HTMLDivElement>(null);
  const quillInstance = useRef<any>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Handle lesson change
  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    // Reset video state
    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  // Notebook Quill Initialization
  useEffect(() => {
    if (activeTab === 'notes' && quillRef.current && !quillInstance.current) {
      const Quill = (window as any).Quill;
      if (Quill) {
        quillInstance.current = new Quill(quillRef.current, {
          theme: 'snow',
          modules: {
            toolbar: [
              ['bold', 'italic', 'underline'],
              [{ 'list': 'ordered'}, { 'list': 'bullet' }],
              ['link', 'blockquote', 'code-block'],
              ['clean']
            ]
          }
        });

        // Set initial content
        const initialContent = user.notes?.[activeLesson.id] || '';
        quillInstance.current.root.innerHTML = initialContent;

        const handleUpdate = () => {
          const html = quillInstance.current.root.innerHTML;
          onNotesUpdate(activeLesson.id, html);
        };

        quillInstance.current.on('text-change', handleUpdate);

        return () => {
          if (quillInstance.current) {
            quillInstance.current.off('text-change', handleUpdate);
            quillInstance.current = null;
          }
        };
      }
    }
  }, [activeTab, activeLesson.id, user.notes, onNotesUpdate]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  // Video Source Management
  const videoSrc = useMemo(() => {
    if (!activeLesson.videoUrl) return '';
    return activeLesson.videoUrl;
  }, [activeLesson.videoUrl]);

  // Video Controls
  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA' || document.activeElement?.classList.contains('ql-editor')) return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className="flex flex-col h-screen bg-[#020617] overflow-hidden">
      {/* Small Header */}
      <header className="px-6 md:px-10 py-3 border-b border-slate-800 bg-slate-950/80 backdrop-blur-xl flex items-center justify-between shrink-0 z-50">
        <button 
          onClick={onBack} 
          className="group flex items-center space-x-2 text-slate-500 hover:text-white transition-all"
        >
          <div className="w-7 h-7 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all">
            <i className="fas fa-arrow-left text-[9px]"></i>
          </div>
          <span className="text-[8px] font-black uppercase tracking-[0.2em]">Close</span>
        </button>

        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 text-[8px] font-black text-indigo-400/70 uppercase tracking-widest px-2.5 py-1 rounded-full border border-indigo-500/10">
            <span className="w-1 h-1 bg-indigo-500/50 rounded-full animate-pulse"></span>
            <span>Focus Mode</span>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className="bg-black aspect-video relative group flex items-center justify-center overflow-hidden max-h-[70vh]">
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[1px] cursor-pointer">
                    <div className="w-16 h-16 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95">
                      <i className="fas fa-play ml-0.5"></i>
                    </div>
                  </div>
                )}
                <div className={`absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/90 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-2 opacity-0 pointer-events-none'}`}>
                  <div className="relative group/progress mb-3">
                    <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-0.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                    <div className="absolute top-0 left-0 h-0.5 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                  </div>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-5 text-white">
                      <button onClick={togglePlay} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                      <div className="flex items-center space-x-3 group/volume">
                        <button onClick={toggleMute} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-16 transition-all duration-300 h-0.5 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[9px] font-black tracking-[0.2em] opacity-40">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-1.5">/</span> {formatTime(duration)}</span>
                    </div>
                    <button onClick={toggleFullscreen} className="text-white text-base hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </>
            ) : (
              <div className="text-slate-800 flex flex-col items-center">
                <div className="w-12 h-12 rounded-full bg-slate-900 flex items-center justify-center mb-4 border border-slate-800">
                  <i className="fas fa-video-slash text-base opacity-20"></i>
                </div>
                <p className="text-[8px] font-black uppercase tracking-[0.3em] opacity-30">Academic Feed</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto p-4 md:p-10">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 border-b border-slate-800/40">
               <div className="flex space-x-6 overflow-x-auto no-scrollbar pb-px">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notebook', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-3 text-[8px] font-black uppercase tracking-[0.3em] transition-all border-b-2 flex items-center space-x-2 whitespace-nowrap ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-[10px]`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`mb-3 md:mb-0 px-3 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all border ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-1.5`}></i> {isReading ? 'Audio Link...' : 'TTS'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <div className="text-slate-400 leading-relaxed text-base ql-editor px-0" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-12 pt-8 border-t border-slate-800/60">
                       <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] mb-6">Module Assets</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-3 bg-slate-900/30 border border-slate-800/60 rounded-xl hover:border-indigo-500/30 transition-all group">
                               <div className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-indigo-400/60 mr-3 shadow-sm group-hover:bg-indigo-600 group-hover:text-white transition-all"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'} text-xs`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-[10px] font-bold text-slate-300 truncate leading-tight">{res.title}</p>
                                  <p className="text-[7px] font-black text-slate-600 uppercase tracking-widest mt-0.5">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-8">
                  <div>
                    <h2 className="text-lg font-black text-white uppercase tracking-tight">Assessment</h2>
                    <p className="text-slate-700 text-[7px] font-black uppercase tracking-[0.2em] mt-1">Neural Verification Chain</p>
                  </div>

                  {quizState.complete ? (
                    <div className="bg-slate-900/50 border border-slate-800 rounded-3xl p-10 text-center shadow-xl">
                      <div className="w-16 h-16 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl border border-indigo-500/20 shadow-inner"><i className="fas fa-star-half-stroke"></i></div>
                      <h3 className="text-xl font-black text-white mb-2 uppercase">Complete</h3>
                      <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mb-8">Score: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all">Retry</button>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/30 border border-slate-800/40 rounded-2xl p-6 shadow-sm">
                          <p className="text-[7px] font-black text-slate-700 uppercase tracking-widest mb-4">Query 0{qIdx + 1}</p>
                          <p className="text-base font-bold text-slate-100 mb-6 leading-tight">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-4 rounded-xl text-left text-[11px] font-bold transition-all border flex items-center space-x-3 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600/20 border-indigo-500/50 text-white translate-y-[-0.5px]' : 'bg-slate-950/20 border-slate-800/40 text-slate-500 hover:border-slate-700'}`}>
                                <span className={`w-6 h-6 rounded-md flex items-center justify-center text-[8px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/10' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[9px] uppercase tracking-[0.3em] shadow-lg">Finalize Response</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h2 className="text-lg font-black text-white uppercase tracking-tight">Notebook</h2>
                    <span className="text-[7px] font-black text-slate-700 uppercase tracking-widest bg-slate-900/30 px-2.5 py-1 rounded-full border border-slate-800">Neural Sync Active</span>
                  </div>
                  <div className="bg-slate-950 border border-slate-800 rounded-2xl overflow-hidden shadow-inner min-h-[400px]">
                    <div ref={quillRef} className="text-slate-300 min-h-[400px]"></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Small AI FAB */}
        <button onClick={() => setIsAiOpen(!isAiOpen)} className={`fixed bottom-6 right-6 w-12 h-12 rounded-xl flex items-center justify-center transition-all shadow-xl z-[100] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-105 active:scale-95'}`}>
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-base`}></i>
        </button>

        <div className={`fixed inset-y-0 right-0 w-full md:w-[380px] bg-slate-950 border-l border-slate-800 z-[90] transition-transform duration-500 ease-out shadow-2xl ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

export default CourseView;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson, User, QuizAttempt } from '../types';

interface DashboardProps {
  user: User;
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user,
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);
  const [lessonSearch, setLessonSearch] = useState('');

  const activeCourse = useMemo(() => 
    courses.find(c => c.id === (selectedCourseId || courses[0]?.id)) || null
  , [courses, selectedCourseId]);

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  const timeRemaining = useMemo(() => {
    if (!activeCourse?.expiryDate) return null;
    const now = new Date();
    const expiry = new Date(activeCourse.expiryDate);
    const diff = expiry.getTime() - now.getTime();
    const days = Math.ceil(diff / (1000 * 60 * 60 * 24));

    if (days < 0) return "Access Expired";
    if (days === 0) return "Expires Today";
    if (days === 1) return "1 day remaining";
    return `${days} days remaining`;
  }, [activeCourse]);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-20 h-20 md:w-32 md:h-32 bg-slate-900 text-indigo-400 rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-2xl">
          <i className="fas fa-satellite-dish text-3xl md:text-4xl animate-pulse"></i>
        </div>
        <h2 className="text-2xl md:text-4xl font-black text-slate-100 mb-6 px-4 tracking-tighter">Your learning portal is waiting.</h2>
        <p className="text-slate-500 mb-10 max-w-md text-sm font-medium">Explore the curriculum and enroll in expert programs to initialize your neural journey.</p>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-10 py-5 bg-indigo-600 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-2xl shadow-indigo-600/30 active:scale-95 transition-all">Launch Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubjectId(subj.id);
    setSelectedSubSubjectId(null);
    setSelectedUnitId(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubjectId(ss.id);
    setSelectedUnitId(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnitId(unit.id);
  };

  const handleBack = () => {
    if (selectedUnit) setSelectedUnitId(null);
    else if (selectedSubSubject) setSelectedSubSubjectId(null);
    else if (selectedSubject) setSelectedSubjectId(null);
  };

  const filteredLessons = useMemo(() => {
    let list = [];
    if (selectedUnit) {
      list = activeCourse.lessons.filter(l => 
        l.subjectId === selectedSubjectId && 
        l.subSubjectId === selectedSubSubjectId &&
        l.unitId === selectedUnitId
      );
    } else if (!selectedSubject) {
      list = activeCourse.lessons.filter(l => !l.subjectId);
    }

    if (lessonSearch.trim()) {
      list = list.filter(l => l.title.toLowerCase().includes(lessonSearch.toLowerCase()));
    }
    return list;
  }, [activeCourse.lessons, selectedSubjectId, selectedSubSubjectId, selectedUnitId, selectedUnit, selectedSubject, lessonSearch]);

  const mainTitle = useMemo(() => {
    if (selectedUnit) return selectedUnit.name;
    if (selectedSubSubject) return selectedSubSubject.name;
    if (selectedSubject) return selectedSubject.name;
    return activeCourse.title;
  }, [selectedSubject, selectedSubSubject, selectedUnit, activeCourse.title]);

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  }, []);

  const isInsideFocusedUnit = !!selectedUnitId;

  return (
    <div className={`space-y-8 md:space-y-12 animate-in fade-in duration-500 max-w-6xl mx-auto ${isInsideFocusedUnit ? 'h-full flex flex-col pt-0' : ''}`}>

      {!isInsideFocusedUnit && (
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
          <div>
            <h2 className="text-sm font-black text-slate-500 uppercase tracking-[0.3em] mb-1">{greeting}, {user.name.split(' ')[0]}!</h2>
            <h1 className="text-2xl md:text-3xl font-black text-white tracking-tighter">Ready to accelerate?</h1>
          </div>

          <div className="flex items-center space-x-3 w-full md:w-auto">
            <div className="relative flex-1 md:flex-none">
              <button 
                onClick={() => setShowCoursePicker(!showCoursePicker)}
                className="w-full flex items-center justify-between space-x-4 px-5 py-3 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500 transition-all group shadow-xl"
              >
                <div className="flex items-center space-x-3 overflow-hidden">
                  <img src={activeCourse.thumbnail} className="w-6 h-6 rounded-md object-cover border border-slate-800" alt="" />
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest truncate max-w-[140px]">{activeCourse.title}</span>
                </div>
                <i className={`fas fa-chevron-down text-[10px] text-slate-600 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
              </button>
              {showCoursePicker && (
                <div className="absolute top-full right-0 mt-3 w-80 bg-slate-900/95 backdrop-blur-xl border border-slate-800 rounded-3xl shadow-[0_32px_64px_-16px_rgba(0,0,0,0.8)] z-[100] p-3 animate-in zoom-in-95 duration-200">
                  <p className="px-4 py-2 text-[8px] font-black text-slate-600 uppercase tracking-[0.3em]">Program Registry</p>
                  <div className="space-y-1 mt-1">
                    {courses.map(c => (
                      <button 
                        key={c.id}
                        onClick={() => {
                          onSelectCourse(c.id);
                          setShowCoursePicker(false);
                          setSelectedSubjectId(null);
                          setSelectedSubSubjectId(null);
                          setSelectedUnitId(null);
                        }}
                        className={`w-full text-left p-4 rounded-2xl transition-all flex items-center space-x-4 group border ${activeCourse.id === c.id ? 'bg-indigo-600/10 border-indigo-500/20' : 'hover:bg-slate-800 border-transparent'}`}
                      >
                        <img src={c.thumbnail} className="w-12 h-12 rounded-xl object-cover border border-slate-800 group-hover:scale-105 transition-transform" alt="" />
                        <div className="min-w-0">
                          <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                          <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">
                            {c.lessons.length} Modules • {c.expiryDate ? new Date(c.expiryDate).toLocaleDateString() : 'Lifetime'}
                          </p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {!isInsideFocusedUnit && (
        <div className="px-4 md:px-0">
          <div className="bg-slate-900/40 rounded-[40px] border border-slate-800/60 p-8 md:p-14 relative overflow-hidden group shadow-2xl backdrop-blur-sm">
            {(selectedSubject || selectedSubSubject) && (
              <button 
                onClick={handleBack}
                className="absolute left-6 md:left-10 top-1/2 -translate-y-1/2 w-10 h-10 md:w-14 md:h-14 bg-slate-950 border border-slate-800 rounded-2xl flex items-center justify-center text-slate-500 hover:text-white hover:border-indigo-500/50 transition-all z-20 shadow-2xl"
              >
                <i className="fas fa-chevron-left text-xs"></i>
              </button>
            )}

            <div className="relative z-10 space-y-4 md:space-y-6 text-center">
              <div className="flex items-center justify-center space-x-2 text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">
                {selectedSubject && (
                  <>
                    <span className="hover:text-indigo-400 cursor-pointer transition-colors" onClick={() => {setSelectedSubSubjectId(null); setSelectedUnitId(null);}}>{selectedSubject.name}</span>
                    {selectedSubSubject && (
                      <>
                        <i className="fas fa-chevron-right text-[7px] opacity-30"></i>
                        <span className="hover:text-indigo-400 cursor-pointer transition-colors" onClick={() => setSelectedUnitId(null)}>{selectedSubSubject.name}</span>
                      </>
                    )}
                  </>
                )}
              </div>

              <h1 className="text-2xl md:text-5xl font-black text-white tracking-tighter leading-tight drop-shadow-2xl px-12 md:px-20 max-w-4xl mx-auto">
                {mainTitle}
              </h1>

              {timeRemaining && !selectedSubject && (
                <div className="inline-flex items-center px-5 py-2 bg-indigo-600/10 rounded-full border border-indigo-500/20">
                   <span className={`w-2 h-2 rounded-full mr-3 animate-pulse ${timeRemaining.includes('Expired') ? 'bg-rose-500' : 'bg-emerald-400'}`}></span>
                   <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">{timeRemaining}</span>
                </div>
              )}
            </div>

            <div className="absolute -bottom-24 -left-24 w-96 h-96 bg-indigo-600/10 rounded-full blur-[120px] pointer-events-none group-hover:bg-indigo-600/15 transition-all duration-1000"></div>
          </div>
        </div>
      )}

      <div className={`px-4 md:px-0 pb-12 ${isInsideFocusedUnit ? 'flex-1' : ''}`}>
        <div className={`bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-4 md:p-10 shadow-2xl backdrop-blur-sm min-h-[400px] ${isInsideFocusedUnit ? 'h-full border-none bg-transparent shadow-none p-0 md:p-4' : ''}`}>

          {!selectedSubject && !isInsideFocusedUnit && (
            <div className="space-y-12">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-black text-white uppercase tracking-[0.2em] flex items-center">
                  <i className="fas fa-sitemap mr-4 text-indigo-500"></i> Subject Explorer
                </h3>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5 md:gap-8">
                {(activeCourse.subjects || []).map((subj) => (
                  <button 
                    key={subj.id} 
                    onClick={() => handleSubjectClick(subj)}
                    className="flex flex-col p-8 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-xl active:scale-95 text-left h-full"
                  >
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-110 transition-transform mb-6`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div className="space-y-2 flex-1">
                      <h4 className="text-xl font-black text-slate-100 group-hover:text-white transition-colors tracking-tight">{subj.name}</h4>
                      <p className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em]">{subj.subSubjects.length} Specialized Paths</p>
                    </div>
                    <div className="mt-8 pt-6 border-t border-slate-800/50 flex items-center justify-between text-[10px] font-black uppercase tracking-widest text-slate-500 group-hover:text-indigo-400 transition-colors">
                      <span>Enter Module</span>
                      <i className="fas fa-arrow-right-long group-hover:translate-x-2 transition-transform"></i>
                    </div>
                  </button>
                ))}
              </div>

              {filteredLessons.length > 0 && (
                <div className="space-y-8 pt-10 border-t border-slate-800/50">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">General Resources</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {filteredLessons.map((lesson) => (
                      <button 
                        key={lesson.id} 
                        onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                        className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                      >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center mr-5 transition-colors ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-700 group-hover:text-indigo-400 shadow-inner'}`}>
                          <i className={`fas ${lesson.isExamMode ? 'fa-file-signature' : 'fa-file-lines'}`}></i>
                        </div>
                        <div className="flex-1 text-left text-sm font-bold text-slate-100 group-hover:text-white transition-colors">
                          {lesson.title}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {selectedSubject && !selectedSubSubject && !isInsideFocusedUnit && (
            <div className="space-y-10 animate-in slide-in-from-right-8 duration-500">
               <div className="flex items-center space-x-4 mb-6">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center border ${selectedSubject.color}`}><i className={`fas ${selectedSubject.icon}`}></i></div>
                <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">{selectedSubject.name} Pathways</h3>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {selectedSubject.subSubjects.map((ss) => (
                  <button 
                    key={ss.id} 
                    onClick={() => handleSubSubjectClick(ss)}
                    className="flex flex-col p-7 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-xl active:scale-95 text-left"
                  >
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner mb-5`}><i className="fas fa-folder-tree"></i></div>
                    <span className="text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
                    <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-2">{ss.units.length} Units Available</p>
                  </button>
                ))}
              </div>
            </div>
          )}

          {selectedSubSubject && !selectedUnit && !isInsideFocusedUnit && (
            <div className="space-y-10 animate-in slide-in-from-right-8 duration-500">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center bg-slate-900 text-indigo-400 border border-slate-800 shadow-inner`}><i className="fas fa-layer-group"></i></div>
                  <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">{selectedSubSubject.name} Curriculum</h3>
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {selectedSubSubject.units?.map((unit) => {
                  const hasExam = activeCourse.lessons.some(l => l.unitId === unit.id && l.isExamMode);
                  const lessonCount = activeCourse.lessons.filter(l => l.unitId === unit.id).length;
                  return (
                    <button 
                      key={unit.id} 
                      onClick={() => handleUnitClick(unit)}
                      className={`flex flex-col p-7 bg-slate-950 border rounded-[32px] transition-all group shadow-xl active:scale-95 text-left h-full ${hasExam ? 'border-rose-500/30 hover:border-rose-500/50' : 'border-slate-800/50 hover:border-emerald-500/40'} hover:bg-slate-900`}
                    >
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 border border-slate-800 group-hover:text-white transition-all shadow-inner mb-5 ${hasExam ? 'text-rose-400 group-hover:bg-rose-600' : 'text-emerald-400 group-hover:bg-emerald-600'}`}>
                        <i className={`fas ${hasExam ? 'fa-file-signature' : 'fa-box-open'}`}></i>
                      </div>
                      <span className="text-lg font-black text-slate-100 group-hover:text-white transition-colors leading-tight mb-2">{unit.name}</span>
                      <div className="flex items-center justify-between mt-auto">
                        <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest">{lessonCount} Modules</span>
                        {hasExam && <span className="text-[7px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/5 px-2 py-0.5 rounded border border-rose-500/10">EXAM ACTIVE</span>}
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {selectedUnit && (
            <div className="h-full flex flex-col space-y-3 animate-in slide-in-from-bottom-4 duration-500 bg-[#020617]">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 pb-3 pt-1 border-b border-slate-800/40">
                <div className="flex items-center space-x-3">
                  <button 
                    onClick={handleBack}
                    className="w-7 h-7 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-lg"
                  >
                    <i className="fas fa-arrow-left text-[8px]"></i>
                  </button>
                  <div>
                    <h3 className="text-base font-black text-white tracking-tight uppercase leading-none">{selectedUnit.name}</h3>
                    <p className="text-[7px] font-black text-indigo-400 uppercase tracking-widest mt-0.5">{filteredLessons.length} Modules</p>
                  </div>
                </div>
                <div className="flex items-center bg-slate-900 px-3 py-1.5 rounded-lg border border-slate-800 w-full md:w-56">
                   <i className="fas fa-magnifying-glass text-slate-700 mr-2 text-[9px]"></i>
                   <input type="text" value={lessonSearch} onChange={(e) => setLessonSearch(e.target.value)} placeholder="Filter..." className="w-full bg-transparent border-none focus:ring-0 text-[10px] text-slate-300 font-bold placeholder:text-slate-800" />
                </div>
              </div>

              {filteredLessons.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 flex-1 overflow-y-auto no-scrollbar pb-6">
                  {filteredLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-2.5 bg-slate-900/50 border border-slate-800/40 rounded-xl hover:border-indigo-500/40 hover:bg-slate-950 transition-all group active:scale-98 shadow-sm text-left"
                    >
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black border mr-2.5 transition-all shadow-inner shrink-0 ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-950 text-slate-600 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                        {lesson.isExamMode ? <i className="fas fa-file-signature"></i> : <i className="fas fa-book-open"></i>}
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-slate-200 group-hover:text-white transition-colors text-[11px] leading-tight truncate">{lesson.title}</h4>
                        {lesson.isExamMode && <span className="text-[5px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1 py-0.5 rounded border border-rose-500/20">EXAM</span>}
                      </div>
                      <div className={`w-6 h-6 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white'}`}>
                        <i className="fas fa-play text-[6px] ml-0.5"></i>
                      </div>
                    </button>
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-12 opacity-30 text-center px-6">
                  <i className="fas fa-box-open text-2xl mb-3 text-slate-700"></i>
                  <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Empty</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);

  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  // Notebook Quill Editor Refs
  const quillRef = useRef<HTMLDivElement>(null);
  const quillInstance = useRef<any>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  // Notebook Editor Logic
  useEffect(() => {
    if (activeTab === 'notes' && quillRef.current && !quillInstance.current) {
      const Quill = (window as any).Quill;
      if (Quill) {
        quillInstance.current = new Quill(quillRef.current, {
          theme: 'snow',
          modules: {
            toolbar: [
              ['bold', 'italic', 'underline'],
              [{ 'list': 'ordered'}, { 'list': 'bullet' }],
              ['link', 'blockquote'],
              ['clean']
            ]
          }
        });

        quillInstance.current.root.innerHTML = user.notes?.[activeLesson.id] || '';

        const handleUpdate = () => {
          const html = quillInstance.current.root.innerHTML;
          if (html !== user.notes?.[activeLesson.id]) {
            onNotesUpdate(activeLesson.id, html);
          }
        };

        quillInstance.current.on('text-change', handleUpdate);

        return () => {
          if (quillInstance.current) {
            quillInstance.current.off('text-change', handleUpdate);
            quillInstance.current = null;
          }
        };
      }
    }
  }, [activeTab, activeLesson.id]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  const videoSrc = useMemo(() => activeLesson.videoUrl || '', [activeLesson.videoUrl]);

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA' || document.activeElement?.classList.contains('ql-editor')) return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className="flex flex-col h-screen bg-[#020617] overflow-hidden">
      <header className="px-6 py-4 border-b border-slate-800 bg-slate-950/50 backdrop-blur-xl flex items-center justify-between shrink-0">
        <div className="flex items-center space-x-4">
          <button onClick={onBack} className="group flex items-center space-x-2 text-slate-500 hover:text-white transition-all">
            <div className="w-8 h-8 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all">
              <i className="fas fa-arrow-left text-[10px]"></i>
            </div>
            <span className="text-[9px] font-black uppercase tracking-[0.2em]">Close</span>
          </button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="text-[11px] font-black text-white uppercase tracking-wider">{activeLesson.title}</h2>
        </div>
        <div className="flex items-center space-x-2 text-[8px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-500/10 px-2 py-1 rounded-lg border border-indigo-500/20">
          <span className="w-1 h-1 bg-indigo-400 rounded-full animate-pulse"></span>
          <span>Focus Active</span>
        </div>
      </header>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className="bg-black aspect-video relative group flex items-center justify-center overflow-hidden max-h-[60vh]">
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[1px] cursor-pointer">
                    <div className="w-16 h-16 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95">
                      <i className="fas fa-play ml-0.5"></i>
                    </div>
                  </div>
                )}
                <div className={`absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/90 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0 pointer-events-none'}`}>
                  <div className="relative group/progress mb-3">
                    <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-0.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                    <div className="absolute top-0 left-0 h-0.5 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                  </div>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-6 text-white">
                      <button onClick={togglePlay} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                      <div className="flex items-center space-x-4 group/volume">
                        <button onClick={toggleMute} className="text-base hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-20 transition-all duration-300 h-0.5 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[10px] font-black tracking-[0.2em] opacity-40">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-1.5 opacity-30">/</span> {formatTime(duration)}</span>
                    </div>
                    <button onClick={toggleFullscreen} className="text-white text-base hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </>
            ) : (
              <div className="text-slate-800 flex flex-col items-center">
                <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center mb-4 border border-slate-800">
                  <i className="fas fa-video-slash text-xl opacity-20"></i>
                </div>
                <p className="text-[9px] font-black uppercase tracking-[0.3em] opacity-30">Academic Feed Pending</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto p-6 md:p-12">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 border-b border-slate-800 pb-2">
               <div className="flex space-x-6 overflow-x-auto no-scrollbar">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notebook', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-2 text-[9px] font-black uppercase tracking-[0.3em] transition-all border-b-2 flex items-center space-x-2 whitespace-nowrap ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-[10px]`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`px-3 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all border ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-2`}></i> {isReading ? 'Voice Linking...' : 'Speak'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <div className="text-slate-400 leading-relaxed text-base ql-editor px-0" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-12 pt-8 border-t border-slate-800">
                       <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.3em] mb-6">Asset Library</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-3 bg-slate-900/30 border border-slate-800 rounded-xl hover:border-indigo-500/30 transition-all group">
                               <div className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-indigo-400/60 mr-3 group-hover:bg-indigo-600 group-hover:text-white transition-all"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'} text-xs`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-[10px] font-bold text-slate-200 truncate leading-tight">{res.title}</p>
                                  <p className="text-[7px] font-black text-slate-600 uppercase tracking-widest mt-0.5">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-8">
                  <div className="flex items-center justify-between">
                    <div>
                      <h2 className="text-xl font-black text-white uppercase tracking-tight">Neural Verification</h2>
                      <p className="text-slate-700 text-[8px] font-black uppercase tracking-[0.2em] mt-1">Consistency Check Engaged</p>
                    </div>
                  </div>
                  {quizState.complete ? (
                    <div className="bg-slate-900 border border-slate-800 rounded-3xl p-10 text-center shadow-xl">
                      <div className="w-16 h-16 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl border border-indigo-500/20 shadow-inner"><i className="fas fa-check-double"></i></div>
                      <h3 className="text-xl font-black text-white mb-2 uppercase">Analysis Complete</h3>
                      <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mb-8">Efficiency: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[8px] font-black uppercase tracking-widest transition-all">Re-Verify</button>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/30 border border-slate-800 rounded-2xl p-6 shadow-sm">
                          <p className="text-[8px] font-black text-slate-700 uppercase tracking-widest mb-4">Query 0{qIdx + 1}</p>
                          <p className="text-base font-bold text-slate-100 mb-6 leading-tight">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-4 rounded-xl text-left text-xs font-bold transition-all border flex items-center space-x-3 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600/20 border-indigo-500/50 text-white shadow-md translate-y-[-1px]' : 'bg-slate-950/20 border-slate-800/60 text-slate-500 hover:border-slate-700'}`}>
                                <span className={`w-6 h-6 rounded-lg flex items-center justify-center text-[9px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/20' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[9px] uppercase tracking-[0.35em] shadow-lg">Finalize Response</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <h2 className="text-xl font-black text-white uppercase tracking-tight">Notebook</h2>
                    <span className="text-[8px] font-black text-slate-700 uppercase tracking-widest bg-slate-900/50 px-3 py-1 rounded-full border border-slate-800">Neural Syncing Active</span>
                  </div>
                  <div className="bg-slate-950 border border-slate-800 rounded-2xl overflow-hidden shadow-inner min-h-[400px]">
                    <div ref={quillRef} className="text-slate-300 min-h-[400px]"></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <button onClick={() => setIsAiOpen(!isAiOpen)} className={`fixed bottom-8 right-8 w-14 h-14 rounded-2xl flex items-center justify-center transition-all shadow-2xl z-[100] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-110 active:scale-95'}`}>
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-xl`}></i>
        </button>
        <div className={`fixed inset-y-0 right-0 w-full md:w-[380px] bg-slate-950 border-l border-slate-800 z-[90] transition-transform duration-500 ease-in-out shadow-2xl ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

