                   <span className={`w-2 h-2 rounded-full mr-3 animate-pulse ${timeRemaining.includes('Expired') ? 'bg-rose-500' : 'bg-emerald-400'}`}></span>
                   <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">{timeRemaining}</span>
