          <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className={`bg-black aspect-video relative group flex items-center justify-center overflow-hidden transition-all duration-700 ${isCinemaMode ? 'fixed inset-0 z-[105]' : 'max-h-[85vh] shadow-2xl shadow-indigo-900/10'}`}>
            {videoSrc ? (
              <>
                <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
                {!isPlaying && (
