                      <div className="flex items-center space-x-5 group/volume">
                        <button onClick={toggleMute} className="text-lg hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                        <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-24 transition-all duration-300 h-1 bg-slate-800 rounded-full appearance-none accent-white" />
                      </div>
                      <span className="text-[11px] font-black tracking-[0.2em] opacity-50">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-2 opacity-30">/</span> {formatTime(duration)}</span>
