                    <div className="flex items-center space-x-6">
                      <button onClick={() => setIsCinemaMode(!isCinemaMode)} className={`text-lg transition-colors ${isCinemaMode ? 'text-indigo-400' : 'text-white hover:text-indigo-400'}`} title="Theater Mode">
