            <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <div className="text-slate-400 leading-relaxed text-lg ql-editor px-0" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-16 pt-10 border-t border-slate-800">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-8">Asset Repository</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-4 bg-slate-900/30 border border-slate-800 rounded-2xl hover:border-indigo-500/30 transition-all group">
                               <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-indigo-400/60 mr-4 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'} text-base`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-xs font-black text-slate-200 truncate leading-tight">{res.title}</p>
                                  <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">{res.type}</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-10">
                  <div>
                    <h2 className="text-2xl font-black text-white uppercase tracking-tight">Neural Checkpoint</h2>
                    <p className="text-slate-700 text-[10px] font-black uppercase tracking-[0.2em] mt-2">Verification Cycle Engaged</p>
                  </div>
                  {quizState.complete ? (
                    <div className="bg-slate-900 border border-slate-800 rounded-[32px] p-12 text-center shadow-2xl">
                      <div className="w-20 h-20 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-8 text-3xl border border-indigo-500/20 shadow-inner"><i className="fas fa-certificate"></i></div>
                      <h3 className="text-2xl font-black text-white mb-3 uppercase tracking-tight">Assessment Finalized</h3>
                      <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-10">Neural Fidelity: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-10 py-4 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all">Re-initiate</button>
                    </div>
                  ) : (
                    <div className="space-y-8">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/40 border border-slate-800 rounded-[32px] p-8 shadow-md">
                          <p className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-6">Subject Query 0{qIdx + 1}</p>
                          <p className="text-xl font-bold text-slate-100 mb-8 leading-snug">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-5 rounded-2xl text-left text-sm font-bold transition-all border flex items-center space-x-4 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl translate-y-[-2px]' : 'bg-slate-950/20 border-slate-800/60 text-slate-500 hover:border-slate-700'}`}>
                                <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/20' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.4em] shadow-2xl">Finalize Response</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-8">
                  <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-black text-white uppercase tracking-tight">Notebook</h2>
                    <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest bg-slate-900/50 px-4 py-2 rounded-full border border-slate-800">Synced to Neural Cloud</span>
                  </div>
                  <div className="bg-slate-950 border border-slate-800 rounded-[32px] overflow-hidden shadow-inner min-h-[500px]">
                    <div ref={quillRef} className="text-slate-300 min-h-[500px]"></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Small AI FAB */}
        <button onClick={() => setIsAiOpen(!isAiOpen)} className={`fixed bottom-8 right-8 w-16 h-16 rounded-[24px] flex items-center justify-center transition-all shadow-2xl z-[150] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-105 active:scale-95 shadow-indigo-600/30'}`}>
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-xl`}></i>
        </button>

        <div className={`fixed inset-y-0 right-0 w-full md:w-[420px] bg-slate-950 border-l border-slate-800 z-[140] transition-transform duration-500 ease-in-out shadow-[0_0_60px_rgba(0,0,0,0.8)] ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

export default CourseView;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson, User, QuizAttempt } from '../types';

interface DashboardProps {
  user: User;
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user,
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);
  const [lessonSearch, setLessonSearch] = useState('');

  // Define handlers for navigating through the curriculum hierarchy
  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubjectId(subj.id);
    setSelectedSubSubjectId(null);
    setSelectedUnitId(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubjectId(ss.id);
    setSelectedUnitId(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnitId(unit.id);
  };

  const handleBack = () => {
    // Navigate back up the hierarchy by clearing states sequentially
    if (selectedUnitId) {
      setSelectedUnitId(null);
    } else if (selectedSubSubjectId) {
      setSelectedSubSubjectId(null);
    } else if (selectedSubjectId) {
      setSelectedSubjectId(null);
    }
  };

  const activeCourse = useMemo(() => 
    courses.find(c => c.id === (selectedCourseId || courses[0]?.id)) || null
  , [courses, selectedCourseId]);

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  const filteredLessons = useMemo(() => {
    let list = [];
    if (selectedUnit) {
      list = activeCourse?.lessons.filter(l => 
        l.subjectId === selectedSubjectId && 
        l.subSubjectId === selectedSubSubjectId &&
        l.unitId === selectedUnitId
      ) || [];
    } else if (!selectedSubject && activeCourse) {
      list = activeCourse.lessons.filter(l => !l.subjectId) || [];
    }

    if (lessonSearch.trim()) {
      list = list.filter(l => l.title.toLowerCase().includes(lessonSearch.toLowerCase()));
    }
    return list;
  }, [activeCourse, selectedSubjectId, selectedSubSubjectId, selectedUnitId, selectedUnit, selectedSubject, lessonSearch]);

  const isInsideFocusedUnit = !!selectedUnitId;

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  }, []);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-20 h-20 md:w-32 md:h-32 bg-slate-900 text-indigo-400 rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-2xl">
          <i className="fas fa-satellite-dish text-3xl md:text-4xl animate-pulse"></i>
        </div>
        <h2 className="text-2xl md:text-4xl font-black text-slate-100 mb-6 px-4 tracking-tighter">Portal Sync Required</h2>
        <p className="text-slate-500 mb-10 max-w-md text-sm font-medium">Initialize your profile by enrolling in a curriculum to start your neural-linked education.</p>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-10 py-5 bg-indigo-600 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-2xl shadow-indigo-600/30 active:scale-95 transition-all">Launch Catalog</button>
      </div>
    );
  }

  return (
    <div className={`space-y-6 md:space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto ${isInsideFocusedUnit ? 'h-full flex flex-col pt-0' : ''}`}>

      {!isInsideFocusedUnit && (
        <>
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
            <div>
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-[0.3em] mb-1">{greeting}, {user.name.split(' ')[0]}</h2>
              <h1 className="text-2xl md:text-4xl font-black text-white tracking-tighter leading-none">Personal Hub</h1>
            </div>

            <div className="relative w-full md:w-auto">
              <button 
                onClick={() => setShowCoursePicker(!showCoursePicker)}
                className="w-full flex items-center justify-between space-x-4 px-5 py-3 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500 transition-all group shadow-xl"
              >
                <div className="flex items-center space-x-3 overflow-hidden text-left">
                  <img src={activeCourse.thumbnail} className="w-6 h-6 rounded-md object-cover border border-slate-800" alt="" />
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest truncate max-w-[140px]">{activeCourse.title}</span>
                </div>
                <i className={`fas fa-chevron-down text-[10px] text-slate-600 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
              </button>
              {showCoursePicker && (
                <div className="absolute top-full right-0 mt-3 w-80 bg-slate-900/95 backdrop-blur-xl border border-slate-800 rounded-3xl shadow-2xl z-[100] p-3 animate-in zoom-in-95 duration-200">
                  <p className="px-4 py-2 text-[8px] font-black text-slate-600 uppercase tracking-[0.3em]">Program Registry</p>
                  <div className="space-y-1 mt-1">
                    {courses.map(c => (
                      <button 
                        key={c.id}
                        onClick={() => {
                          onSelectCourse(c.id);
                          setShowCoursePicker(false);
                          setSelectedSubjectId(null);
                          setSelectedSubSubjectId(null);
                          setSelectedUnitId(null);
                        }}
                        className={`w-full text-left p-4 rounded-2xl transition-all flex items-center space-x-4 group border ${activeCourse.id === c.id ? 'bg-indigo-600/10 border-indigo-500/20' : 'hover:bg-slate-800 border-transparent'}`}
                      >
                        <img src={c.thumbnail} className="w-12 h-12 rounded-xl object-cover border border-slate-800" alt="" />
                        <div className="min-w-0 text-left">
                          <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                          <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">
                            {c.lessons.length} Modules • Enrolled
                          </p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* New Dashboard Summary Section */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 px-4 md:px-0">
            <div className="lg:col-span-2 bg-gradient-to-br from-indigo-600 to-indigo-800 rounded-[32px] p-8 md:p-10 text-white relative overflow-hidden group">
              <div className="relative z-10">
                <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-80 mb-2">Continue Session</p>
                <h2 className="text-2xl md:text-3xl font-black mb-6 max-w-sm tracking-tight">{activeCourse.lessons[0]?.title || 'Resume learning where you left off'}</h2>
                <button 
                  onClick={() => onCourseClick(activeCourse.id, activeCourse.lessons[0]?.id)}
                  className="px-8 py-4 bg-white text-indigo-700 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 transition-transform"
                >
                  Resume Lesson <i className="fas fa-play ml-3"></i>
                </button>
              </div>
              <div className="absolute top-1/2 -right-12 w-64 h-64 bg-white/10 rounded-full blur-3xl pointer-events-none group-hover:bg-white/20 transition-all duration-1000"></div>
              <i className="fas fa-graduation-cap absolute -bottom-8 -right-8 text-[12rem] opacity-10 rotate-12"></i>
            </div>

            <div className="bg-slate-900 border border-slate-800 rounded-[32px] p-8 flex flex-col justify-between">
              <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-4">Course Momentum</p>
                <div className="flex items-end justify-between mb-2">
                  <span className="text-4xl font-black text-white">78%</span>
                  <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest mb-1">+12% this week</span>
                </div>
                <div className="w-full h-2 bg-slate-950 rounded-full overflow-hidden border border-slate-800/50">
                  <div className="h-full bg-indigo-500 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.5)]" style={{ width: '78%' }}></div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 mt-8 pt-6 border-t border-slate-800/50">
                <div>
                  <p className="text-white font-black text-lg leading-none">12</p>
                  <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">Completed</p>
                </div>
                <div>
                  <p className="text-white font-black text-lg leading-none">4</p>
                  <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">Certificates</p>
                </div>
              </div>
            </div>
          </div>
        </>
      )}

      {/* Content Section */}
      <div className={`px-4 md:px-0 pb-12 ${isInsideFocusedUnit ? 'flex-1' : ''}`}>
        <div className={`${isInsideFocusedUnit ? 'h-full bg-[#020617]' : 'bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-4 md:p-8 shadow-xl backdrop-blur-sm'}`}>

          {/* Dashboard: Top Level Subject Grid */}
          {!selectedSubject && !isInsideFocusedUnit && (
            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <h3 className="text-[11px] font-black text-white uppercase tracking-[0.3em] flex items-center">
                  <i className="fas fa-sitemap mr-4 text-indigo-500"></i> Subject Explorer
                </h3>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
                {(activeCourse.subjects || []).map((subj) => (
                  <button 
                    key={subj.id} 
                    onClick={() => handleSubjectClick(subj)} 
                    className="flex flex-col p-8 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-xl active:scale-95 text-left h-full"
                  >
                    <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-3xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-110 transition-transform mb-6`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div className="space-y-2 flex-1">
                      <h4 className="text-2xl font-black text-slate-100 group-hover:text-white transition-colors tracking-tight">{subj.name}</h4>
                      <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">{subj.subSubjects.length} Specializations</p>
                    </div>
                    <div className="mt-8 pt-6 border-t border-slate-800/30 flex items-center justify-between text-[10px] font-black text-slate-500 group-hover:text-indigo-400 uppercase tracking-widest transition-colors">
                      <span>Enter Module</span>
                      <i className="fas fa-arrow-right-long group-hover:translate-x-2 transition-transform"></i>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* SubSubject Level */}
          {selectedSubject && !selectedSubSubject && !isInsideFocusedUnit && (
