                    <button key={lesson.id} onClick={() => onCourseClick(activeCourse.id, lesson.id)} className="flex items-center p-3.5 bg-slate-950 border border-slate-800/40 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-sm text-left">
