                      <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-slate-200 group-hover:text-white transition-colors text-xs leading-tight truncate">{lesson.title}</h4>
                        {lesson.isExamMode && <span className="text-[6px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1 py-0.5 rounded border border-rose-500/20 mt-1 block w-fit">EXAM</span>}
                      </div>
                      <div className={`w-7 h-7 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white'}`}>
                        <i className="fas fa-play text-[7px] ml-0.5"></i>
                      </div>
                    </button>
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-24 opacity-30 text-center px-6">
                  <i className="fas fa-box-open text-4xl mb-4 text-slate-700"></i>
