                  return (
                    <button key={unit.id} onClick={() => handleUnitClick(unit)} className={`flex flex-col p-10 bg-slate-950 border rounded-[40px] transition-all group shadow-2xl active:scale-95 text-left h-full ${hasExam ? 'border-rose-500/30 hover:border-rose-500/50' : 'border-slate-800/60 hover:border-emerald-500/40'} hover:bg-slate-900`}>
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl bg-slate-900 border border-slate-800 group-hover:text-white transition-all shadow-inner mb-8 ${hasExam ? 'text-rose-400 group-hover:bg-rose-600' : 'text-emerald-400 group-hover:bg-emerald-600'}`}><i className={`fas ${hasExam ? 'fa-file-signature' : 'fa-box-open'}`}></i></div>
                      <span className="text-xl font-black text-slate-100 group-hover:text-white transition-colors leading-tight mb-2">{unit.name}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {/* Module Grid (Inside Unit) */}
          {selectedUnit && (
            <div className="h-full flex flex-col space-y-4 animate-in slide-in-from-bottom-2 duration-500">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 pb-6 pt-2 border-b border-slate-800/50">
                <div className="flex items-center space-x-6">
                  <button onClick={handleBack} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-xl group"><i className="fas fa-arrow-left text-[11px] group-hover:-translate-x-1 transition-transform"></i></button>
                  <div>
                    <h3 className="text-2xl font-black text-white tracking-tight uppercase leading-none">{selectedUnit.name}</h3>
                    <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mt-1.5">{filteredLessons.length} Specialized Modules Mapped</p>
                  </div>
                </div>
                <div className="flex items-center bg-slate-900/80 px-5 py-3 rounded-2xl border border-slate-800 w-full md:w-72 shadow-inner">
                   <i className="fas fa-magnifying-glass text-slate-700 mr-4 text-xs"></i>
                   <input type="text" value={lessonSearch} onChange={(e) => setLessonSearch(e.target.value)} placeholder="Filter sequence..." className="w-full bg-transparent border-none focus:ring-0 text-xs text-slate-300 font-bold placeholder:text-slate-700" />
                </div>
              </div>

              {filteredLessons.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 flex-1 overflow-y-auto no-scrollbar pb-10 pt-4">
                  {filteredLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)} 
                      className="flex items-center p-4 bg-slate-950/40 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-lg text-left"
                    >
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-[11px] font-black border mr-4 transition-all shadow-inner shrink-0 ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-900 text-slate-600 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                        {lesson.isExamMode ? <i className="fas fa-file-signature text-xs"></i> : <i className="fas fa-book-open text-[10px]"></i>}
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-slate-200 group-hover:text-white transition-colors text-xs leading-tight truncate">{lesson.title}</h4>
                        <div className="flex items-center space-x-2 mt-1.5">
                           {lesson.isExamMode ? (
                              <span className="text-[6px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1.5 py-0.5 rounded border border-rose-500/20">EXAM</span>
                           ) : (
                              <span className="text-[6px] font-black text-slate-600 uppercase tracking-widest bg-slate-900 px-1.5 py-0.5 rounded border border-slate-800 group-hover:text-indigo-400/60 group-hover:border-indigo-500/20">{lesson.videoUrl ? 'Video' : 'Reading'}</span>
                           )}
                        </div>
                      </div>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500 shadow-rose-500/20' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white group-hover:shadow-indigo-600/20'}`}>
                        <i className="fas fa-play text-[8px] ml-0.5"></i>
                      </div>
                    </button>
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-28 opacity-30 text-center px-6">
                  <i className="fas fa-box-open text-5xl mb-6 text-slate-700"></i>
                  <p className="text-[11px] font-black text-slate-500 uppercase tracking-widest">No matching modules in this unit</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Course, QuizAttempt, User, Lesson } from '../types';
import AIAssistant from './AIAssistant';
import { speakContent, decodeAudio, decodeAudioData } from '../services/geminiService';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
  onNotesUpdate: (lessonId: string, content: string) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete, onNotesUpdate }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [isReading, setIsReading] = useState(false);
  const [isCinemaMode, setIsCinemaMode] = useState(false);

  const [quizState, setQuizState] = useState({
    complete: false,
    score: 0,
    answers: {} as Record<string, number>
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef<number | null>(null);

  // Notebook Quill Editor Refs
  const quillRef = useRef<HTMLDivElement>(null);
  const quillInstance = useRef<any>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Video Source Detection
  const hasVideo = !!activeLesson.videoUrl;

  useEffect(() => {
    const existingScore = user.quizScores[activeLesson.id];
    setQuizState({
      complete: !!existingScore,
      score: existingScore?.score || 0,
      answers: {}
    });

    if (activeLesson.isExamMode) {
      setActiveTab('quiz');
    } else {
      setActiveTab('overview');
    }

    setIsPlaying(false);
    setProgress(0);
    setIsReading(false);
    setIsCinemaMode(false); // Reset cinema mode on lesson change
  }, [activeLesson.id, user.quizScores, activeLesson.isExamMode]);

  // Notebook Editor Logic
  useEffect(() => {
    if (activeTab === 'notes' && quillRef.current && !quillInstance.current) {
      const Quill = (window as any).Quill;
      if (Quill) {
        quillInstance.current = new Quill(quillRef.current, {
          theme: 'snow',
          modules: {
            toolbar: [
              ['bold', 'italic', 'underline'],
              [{ 'list': 'ordered'}, { 'list': 'bullet' }],
              ['link', 'blockquote', 'formula'],
              ['clean']
            ]
          }
        });

        quillInstance.current.root.innerHTML = user.notes?.[activeLesson.id] || '';

        const handleUpdate = () => {
          const html = quillInstance.current.root.innerHTML;
          if (html !== user.notes?.[activeLesson.id]) {
            onNotesUpdate(activeLesson.id, html);
          }
        };

        quillInstance.current.on('text-change', handleUpdate);

        return () => {
          if (quillInstance.current) {
            quillInstance.current.off('text-change', handleUpdate);
            quillInstance.current = null;
          }
        };
      }
    }
  }, [activeTab, activeLesson.id]);

  const handleReadLesson = async () => {
    if (isReading) {
      setIsReading(false);
      return;
    }

    setIsReading(true);
    const contentText = activeLesson.content.replace(/<[^>]*>?/gm, '');
    const base64Audio = await speakContent(contentText);

    if (base64Audio && isReading) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decodeAudio(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsReading(false);
      source.start();
    } else {
      setIsReading(false);
    }
  };

  const videoSrc = useMemo(() => activeLesson.videoUrl || '', [activeLesson.videoUrl]);

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(() => {});
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    const nextMuted = !isMuted;
    videoRef.current.muted = nextMuted;
    setIsMuted(nextMuted);
  };

  const skipTime = (amount: number) => {
    if (!videoRef.current) return;
    videoRef.current.currentTime += amount;
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    setProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
  };

  const handleLoadedMetadata = () => {
    if (!videoRef.current) return;
    setDuration(videoRef.current.duration);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = (parseFloat(e.target.value) / 100) * videoRef.current.duration;
    videoRef.current.currentTime = time;
    setProgress(parseFloat(e.target.value));
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) window.clearTimeout(controlsTimeoutRef.current);
    controlsTimeoutRef.current = window.setTimeout(() => {
      if (isPlaying) setShowControls(false);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA' || document.activeElement?.classList.contains('ql-editor')) return;
      switch(e.code) {
        case 'Space': e.preventDefault(); togglePlay(); break;
        case 'KeyM': toggleMute(); break;
        case 'ArrowRight': skipTime(10); break;
        case 'ArrowLeft': skipTime(-10); break;
        case 'KeyF': toggleFullscreen(); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isPlaying, isMuted]);

  const handleSubmitExam = useCallback(() => {
    const questions = activeLesson.quiz || [];
    if (questions.length === 0) return;
    let score = 0;
    questions.forEach(q => {
      if (quizState.answers[q.id] === q.correctAnswer) score++;
    });
    const attempt: QuizAttempt = { score, total: questions.length, date: new Date() };
    setQuizState(prev => ({ ...prev, complete: true, score }));
    onQuizComplete(activeLesson.id, attempt);
  }, [activeLesson, quizState.answers, onQuizComplete]);

  return (
    <div className={`flex flex-col h-screen bg-[#020617] overflow-hidden transition-all duration-700 ${isCinemaMode ? 'bg-black' : ''}`}>
      {/* Dynamic Header */}
      <header className={`px-6 py-4 border-b border-slate-800 bg-slate-950/50 backdrop-blur-xl flex items-center justify-between shrink-0 z-[100] transition-all duration-700 ${isCinemaMode ? '-translate-y-full opacity-0' : 'translate-y-0 opacity-100'}`}>
        <div className="flex items-center space-x-6">
          <button onClick={onBack} className="group flex items-center space-x-3 text-slate-500 hover:text-white transition-all">
            <div className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all shadow-xl">
              <i className="fas fa-arrow-left text-[11px]"></i>
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">Exit Unit</span>
          </button>
          <div className="h-8 w-px bg-slate-800"></div>
          <div className="flex flex-col">
            <h2 className="text-[12px] font-black text-white uppercase tracking-wider line-clamp-1">{activeLesson.title}</h2>
            <p className="text-[8px] font-bold text-slate-600 uppercase tracking-widest mt-0.5">{course.title}</p>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          {hasVideo && (
            <button 
              onClick={() => setIsCinemaMode(!isCinemaMode)} 
              className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all ${isCinemaMode ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white hover:border-indigo-500/30 shadow-xl'}`}
              title="Theater Mode"
            >
               <i className="fas fa-film text-xs"></i>
            </button>
          )}
          <div className="flex items-center space-x-2.5 text-[8px] font-black text-indigo-400 uppercase tracking-[0.3em] bg-indigo-500/10 px-3 py-1.5 rounded-xl border border-indigo-500/20 shadow-inner">
            <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(99,102,241,0.8)]"></span>
            <span>Focus Active</span>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <div className="flex-1 overflow-y-auto no-scrollbar">
          {/* Cinema mode exit button overlay */}
          {isCinemaMode && (
            <button 
              onClick={() => setIsCinemaMode(false)}
              className="fixed top-8 left-8 z-[110] w-14 h-14 bg-white/5 backdrop-blur-xl rounded-2xl flex items-center justify-center text-white border border-white/10 hover:bg-white/10 transition-all shadow-2xl"
            >
              <i className="fas fa-chevron-left"></i>
            </button>
          )}

          {/* Conditional Video Player Area */}
          {hasVideo ? (
            <div ref={containerRef} onMouseMove={handleMouseMove} onContextMenu={(e) => e.preventDefault()} className={`bg-black aspect-video relative group flex items-center justify-center overflow-hidden transition-all duration-700 ${isCinemaMode ? 'fixed inset-0 z-[105]' : 'max-h-[80vh] shadow-[0_0_80px_rgba(0,0,0,0.6)]'}`}>
              <video ref={videoRef} src={videoSrc} className="w-full h-full object-contain" onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} onClick={togglePlay} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} disablePictureInPicture />
              {!isPlaying && (
                <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[1px] cursor-pointer">
                  <div className="w-24 h-24 bg-indigo-600/90 text-white rounded-full flex items-center justify-center text-3xl shadow-2xl transform transition-transform hover:scale-110 active:scale-95 border-2 border-white/10">
                    <i className="fas fa-play ml-1.5"></i>
                  </div>
                </div>
              )}
              <div className={`absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-black/95 via-black/40 to-transparent transition-all duration-500 ${showControls ? 'translate-y-0 opacity-100' : 'translate-y-8 opacity-0 pointer-events-none'}`}>
                <div className="relative group/progress mb-5">
                  <input type="range" min="0" max="100" step="0.1" value={progress} onChange={handleSeek} className="w-full h-1.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 relative z-10" />
                  <div className="absolute top-0 left-0 h-1.5 bg-indigo-600 rounded-full pointer-events-none" style={{ width: `${progress}%` }}></div>
                </div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-10 text-white">
                    <button onClick={togglePlay} className="text-2xl hover:text-indigo-400 transition-colors"><i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i></button>
                    <div className="flex items-center space-x-6 group/volume">
                      <button onClick={toggleMute} className="text-xl hover:text-indigo-400 transition-colors"><i className={`fas ${isMuted || volume === 0 ? 'fa-volume-mute' : 'fa-volume-up'}`}></i></button>
                      <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={(e) => { const v = parseFloat(e.target.value); setVolume(v); if (videoRef.current) videoRef.current.volume = v; setIsMuted(v === 0); }} className="w-0 group-hover/volume:w-28 transition-all duration-300 h-1 bg-slate-800 rounded-full appearance-none accent-white" />
                    </div>
                    <span className="text-[12px] font-black tracking-[0.3em] opacity-40">{formatTime(videoRef.current?.currentTime || 0)} <span className="mx-2 opacity-20">/</span> {formatTime(duration)}</span>
                  </div>
                  <div className="flex items-center space-x-8">
                    <button onClick={() => setIsCinemaMode(!isCinemaMode)} className={`text-xl transition-colors ${isCinemaMode ? 'text-indigo-400' : 'text-white hover:text-indigo-400'}`} title="Theater Mode">
                      <i className="fas fa-film"></i>
                    </button>
                    <button onClick={toggleFullscreen} className="text-white text-xl hover:text-indigo-400 transition-colors"><i className="fas fa-expand"></i></button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            /* Text-only Header Replacement */
            <div className="h-48 bg-gradient-to-br from-indigo-900/40 via-slate-950 to-[#020617] flex items-center justify-center relative border-b border-slate-800/50">
               <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
               <div className="relative text-center">
                  <div className="w-16 h-16 rounded-3xl bg-indigo-600/10 text-indigo-400 flex items-center justify-center mx-auto mb-4 border border-indigo-500/20 shadow-2xl">
                    <i className="fas fa-file-lines text-2xl"></i>
                  </div>
                  <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500">Academic Theory Module</p>
               </div>
            </div>
          )}

          <div className={`max-w-4xl mx-auto p-8 md:p-14 transition-opacity duration-700 ${isCinemaMode ? 'opacity-0' : 'opacity-100'}`}>
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12 border-b border-slate-800/50 pb-2">
               <div className="flex space-x-10 overflow-x-auto no-scrollbar">
                {[
                  { id: 'overview', label: 'Theory', icon: 'fa-book-open' },
                  { id: 'quiz', label: 'Quiz', icon: 'fa-vial' },
                  { id: 'notes', label: 'Notebook', icon: 'fa-pen-nib' }
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-4 text-[11px] font-black uppercase tracking-[0.4em] transition-all border-b-2 flex items-center space-x-3 whitespace-nowrap ${activeTab === tab.id ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                    <i className={`fas ${tab.icon} text-xs`}></i>
                    <span>{tab.label}</span>
                  </button>
                ))}
               </div>
               {activeTab === 'overview' && (
                 <button onClick={handleReadLesson} disabled={isReading} className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border shadow-lg ${isReading ? 'bg-indigo-600 border-indigo-500 text-white animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-indigo-400 hover:border-indigo-500/50'}`}>
                    <i className={`fas ${isReading ? 'fa-volume-up' : 'fa-ear-listen'} mr-3`}></i> {isReading ? 'Reading aloud...' : 'Spoken Audio'}
                 </button>
               )}
            </div>

            <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
              {activeTab === 'overview' && (
                <div className="prose prose-invert max-w-none">
                  <div className={`text-slate-300 leading-relaxed text-lg ql-editor px-0 ${!hasVideo ? 'font-serif' : ''}`} dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
                  {activeLesson.resources && activeLesson.resources.length > 0 && (
                    <div className="mt-20 pt-12 border-t border-slate-800">
                       <h3 className="text-[11px] font-black text-slate-600 uppercase tracking-[0.4em] mb-10">Asset Repository</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                          {activeLesson.resources.map(res => (
                            <a key={res.id} href={res.url} target="_blank" rel="noreferrer" className="flex items-center p-5 bg-slate-900/30 border border-slate-800 rounded-[28px] hover:border-indigo-500/40 hover:bg-slate-900/50 transition-all group shadow-sm">
                               <div className="w-12 h-12 rounded-2xl bg-slate-950 flex items-center justify-center text-indigo-400/70 mr-5 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-xl"><i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play-circle' : 'fa-link'} text-xl`}></i></div>
                               <div className="min-w-0">
                                  <p className="text-sm font-black text-slate-100 truncate leading-tight group-hover:text-indigo-400 transition-colors">{res.title}</p>
                                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1.5">{res.type} document</p>
                               </div>
                            </a>
                          ))}
                       </div>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'quiz' && (
                <div className="space-y-12">
                  <div>
                    <h2 className="text-3xl font-black text-white uppercase tracking-tight">Neural Checkpoint</h2>
                    <p className="text-slate-700 text-[11px] font-black uppercase tracking-[0.3em] mt-2">Analytical Cycle Engaged</p>
                  </div>
                  {quizState.complete ? (
                    <div className="bg-slate-900 border border-slate-800 rounded-[48px] p-16 text-center shadow-[0_40px_100px_rgba(0,0,0,0.4)]">
                      <div className="w-24 h-24 bg-indigo-600/10 text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-10 text-4xl border border-indigo-500/20 shadow-inner"><i className="fas fa-award"></i></div>
                      <h3 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">Verified</h3>
                      <p className="text-slate-500 text-[11px] font-black uppercase tracking-widest mb-12">Retention Level: {quizState.score} / {activeLesson.quiz?.length}</p>
                      <button onClick={() => setQuizState({ complete: false, score: 0, answers: {} })} className="px-12 py-5 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl">Re-initiate Test</button>
                    </div>
                  ) : (
                    <div className="space-y-10">
                      {(activeLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="bg-slate-900/40 border border-slate-800 rounded-[40px] p-10 shadow-xl group hover:border-indigo-500/20 transition-all">
                          <p className="text-[10px] font-black text-slate-700 uppercase tracking-widest mb-8">Query Identity 0{qIdx + 1}</p>
                          <p className="text-2xl font-bold text-slate-100 mb-10 leading-snug">{q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                            {q.options.map((opt, oIdx) => (
                              <button key={oIdx} onClick={() => setQuizState(prev => ({ ...prev, answers: { ...prev.answers, [q.id]: oIdx } }))} className={`p-6 rounded-3xl text-left text-base font-bold transition-all border flex items-center space-x-5 ${quizState.answers[q.id] === oIdx ? 'bg-indigo-600 border-indigo-500 text-white shadow-2xl translate-y-[-4px]' : 'bg-slate-950/40 border-slate-800/80 text-slate-500 hover:border-slate-700'}`}>
                                <span className={`w-10 h-10 rounded-xl flex items-center justify-center text-[11px] font-black border ${quizState.answers[q.id] === oIdx ? 'bg-indigo-500 border-white/30' : 'bg-slate-900 border-slate-800'}`}>{String.fromCharCode(65 + oIdx)}</span>
                                <span className="flex-1">{opt}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      ))}
                      {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={handleSubmitExam} className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[32px] font-black text-[11px] uppercase tracking-[0.45em] shadow-2xl shadow-indigo-600/30">Finalize Responses</button>}
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="space-y-10 animate-in fade-in duration-500">
                  <div className="flex items-center justify-between">
                    <h2 className="text-3xl font-black text-white uppercase tracking-tight">Notebook</h2>
                    <div className="flex items-center space-x-3 text-[10px] font-black text-slate-700 uppercase tracking-widest bg-slate-900/50 px-5 py-2.5 rounded-full border border-slate-800">
                      <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse mr-1"></span>
                      Cloud Sync Active
                    </div>
                  </div>
                  <div className="bg-slate-950 border border-slate-800 rounded-[48px] overflow-hidden shadow-[inset_0_2px_40px_rgba(0,0,0,0.8)] min-h-[550px]">
                    <div ref={quillRef} className="text-slate-300 min-h-[550px]"></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Floating AI Action Button */}
        <button 
          onClick={() => setIsAiOpen(!isAiOpen)} 
          className={`fixed bottom-10 right-10 w-20 h-20 rounded-[30px] flex items-center justify-center transition-all shadow-[0_20px_60px_-15px_rgba(99,102,241,0.6)] z-[150] group ${isAiOpen ? 'bg-rose-600 text-white rotate-90 scale-90' : 'bg-indigo-600 text-white hover:scale-110 active:scale-95'}`}
        >
          <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-sparkles'} text-3xl`}></i>
          {!isAiOpen && (
            <div className="absolute right-full mr-8 opacity-0 group-hover:opacity-100 transition-all pointer-events-none translate-x-4 group-hover:translate-x-0">
               <div className="bg-slate-900 border border-slate-800 px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-indigo-400 whitespace-nowrap shadow-2xl">
                 Neural Assistant
               </div>
            </div>
          )}
        </button>

        <div className={`fixed inset-y-0 right-0 w-full md:w-[460px] bg-slate-950 border-l border-slate-800 z-[140] transition-transform duration-700 cubic-bezier(0.4, 0, 0.2, 1) shadow-[0_0_120px_rgba(0,0,0,0.9)] ${isAiOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          {activeLesson && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </div>
    </div>
  );
};

export default CourseView;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson, User, QuizAttempt } from '../types';

interface DashboardProps {
  user: User;
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user,
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);
  const [lessonSearch, setLessonSearch] = useState('');

  const activeCourse = useMemo(() => 
    courses.find(c => c.id === (selectedCourseId || courses[0]?.id)) || null
  , [courses, selectedCourseId]);

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubjectId(subj.id);
    setSelectedSubSubjectId(null);
    setSelectedUnitId(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubjectId(ss.id);
    setSelectedUnitId(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnitId(unit.id);
  };

  const handleBack = () => {
    if (selectedUnitId) setSelectedUnitId(null);
    else if (selectedSubSubjectId) setSelectedSubSubjectId(null);
    else if (selectedSubjectId) setSelectedSubjectId(null);
  };

  const filteredLessons = useMemo(() => {
    let list: Lesson[] = [];
    if (selectedUnit) {
      list = activeCourse?.lessons.filter(l => 
        l.subjectId === selectedSubjectId && 
        l.subSubjectId === selectedSubSubjectId &&
        l.unitId === selectedUnitId
      ) || [];
    } else if (!selectedSubject && activeCourse) {
      list = activeCourse.lessons.filter(l => !l.subjectId) || [];
    }

    if (lessonSearch.trim()) {
      list = list.filter(l => l.title.toLowerCase().includes(lessonSearch.toLowerCase()));
    }
    return list;
  }, [activeCourse, selectedSubjectId, selectedSubSubjectId, selectedUnitId, selectedUnit, selectedSubject, lessonSearch]);

  const isInsideFocusedUnit = !!selectedUnitId;
  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  }, []);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-20 h-20 bg-slate-900 text-indigo-400 rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-2xl">
          <i className="fas fa-satellite-dish text-3xl animate-pulse"></i>
        </div>
        <h2 className="text-2xl md:text-4xl font-black text-slate-100 mb-6 tracking-tighter">Portal Sync Required</h2>
        <p className="text-slate-500 mb-10 max-w-md text-sm font-medium">Initialize your profile by enrolling in a curriculum to start your neural-linked education.</p>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-10 py-5 bg-indigo-600 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-2xl shadow-indigo-600/30 active:scale-95 transition-all">Launch Catalog</button>
      </div>
    );
  }

  return (
    <div className={`space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-6xl mx-auto ${isInsideFocusedUnit ? 'h-full flex flex-col pt-0' : ''}`}>

      {!isInsideFocusedUnit && (
        <>
          {/* Header Row */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
            <div className="animate-in slide-in-from-left-4 duration-500">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-[0.3em] mb-1">{greeting}, {user.name.split(' ')[0]}</h2>
              <h1 className="text-3xl md:text-4xl font-black text-white tracking-tighter leading-none">Learning Center</h1>
            </div>

            <div className="relative w-full md:w-auto">
              <button 
                onClick={() => setShowCoursePicker(!showCoursePicker)}
                className="w-full flex items-center justify-between space-x-6 px-6 py-4 bg-slate-900 border border-slate-800 rounded-3xl hover:border-indigo-500 transition-all group shadow-xl"
              >
                <div className="flex items-center space-x-4 overflow-hidden text-left">
                  <div className="w-10 h-10 rounded-xl overflow-hidden border border-slate-800">
                    <img src={activeCourse.thumbnail} className="w-full h-full object-cover" alt="" />
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest truncate max-w-[140px]">{activeCourse.title}</span>
                    <span className="text-[8px] font-bold text-slate-500 uppercase">Change Program</span>
                  </div>
                </div>
                <i className={`fas fa-chevron-down text-[10px] text-slate-600 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
