                    {courses.map(c => (
                      <button 
                        key={c.id}
                        onClick={() => {
                          onSelectCourse(c.id);
                          setShowCoursePicker(false);
                          handleBack(); // Reset navigation
                        }}
                        className={`w-full text-left p-4 rounded-2xl transition-all flex items-center space-x-4 group border ${activeCourse.id === c.id ? 'bg-indigo-600/10 border-indigo-500/20' : 'hover:bg-slate-800 border-transparent'}`}
                      >
                        <img src={c.thumbnail} className="w-10 h-10 rounded-xl object-cover border border-slate-800" alt="" />
                        <div className="min-w-0 text-left">
                          <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                          <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-0.5">
                            {c.lessons.length} Modules • Enrolled
                          </p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Momentum & Resume Section */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 px-4 md:px-0 animate-in slide-in-from-bottom-6 duration-700 delay-150">
            <div className="lg:col-span-2 bg-gradient-to-br from-indigo-600 to-indigo-900 rounded-[40px] p-8 md:p-12 text-white relative overflow-hidden group shadow-2xl shadow-indigo-900/20">
              <div className="relative z-10 flex flex-col h-full justify-between min-h-[220px] text-left">
                <div>
                  <div className="inline-flex items-center px-3 py-1 bg-white/10 rounded-full border border-white/20 text-[9px] font-black uppercase tracking-widest mb-6">
                    <span className="w-2 h-2 bg-emerald-400 rounded-full mr-2 animate-pulse"></span>
                    Ready to continue?
                  </div>
                  <h2 className="text-3xl md:text-4xl font-black mb-4 max-w-lg tracking-tight leading-tight">
                    {activeCourse.lessons[0]?.title || 'Resume your specialized learning track'}
                  </h2>
                  <p className="text-indigo-100 text-sm font-medium opacity-80 max-w-md">Pick up exactly where you left off in your professional curriculum.</p>
                </div>
                <div className="pt-8">
                  <button 
                    onClick={() => onCourseClick(activeCourse.id, activeCourse.lessons[0]?.id)}
                    className="px-10 py-4 bg-white text-indigo-700 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-2xl hover:bg-slate-100 hover:scale-105 active:scale-95 transition-all"
                  >
                    Resume Session <i className="fas fa-arrow-right-long ml-3"></i>
                  </button>
                </div>
              </div>
              <i className="fas fa-graduation-cap absolute -bottom-10 -right-10 text-[18rem] opacity-10 rotate-12 group-hover:rotate-[20deg] group-hover:scale-110 transition-all duration-1000"></i>
              <div className="absolute top-0 right-0 w-80 h-80 bg-white/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
            </div>

            <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-8 md:p-10 flex flex-col justify-between shadow-xl relative overflow-hidden group">
              <div className="text-left">
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-4">Course Momentum</p>
                <div className="flex items-end justify-between mb-3">
                  <span className="text-5xl font-black text-white tracking-tighter">72%</span>
                  <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">+8% increase</span>
                    <span className="text-[8px] font-bold text-slate-600 uppercase tracking-tighter">Compared to last week</span>
                  </div>
                </div>
                <div className="w-full h-2.5 bg-slate-950 rounded-full overflow-hidden border border-slate-800/50 p-0.5">
                  <div className="h-full bg-indigo-500 rounded-full shadow-[0_0_20px_rgba(99,102,241,0.6)]" style={{ width: '72%' }}></div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 mt-10 pt-8 border-t border-slate-800/50 text-left">
                <div className="space-y-1">
                  <p className="text-white font-black text-2xl leading-none">14</p>
                  <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Completed</p>
                </div>
                <div className="space-y-1">
                  <p className="text-white font-black text-2xl leading-none">03</p>
                  <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Rewards</p>
                </div>
              </div>

              <div className="absolute top-0 right-0 p-6 opacity-0 group-hover:opacity-10 transition-opacity">
                <i className="fas fa-chart-line text-6xl text-indigo-400"></i>
              </div>
            </div>
          </div>
        </>
      )}

      {/* Exploration Section */}
      <div className={`px-4 md:px-0 pb-20 ${isInsideFocusedUnit ? 'flex-1' : ''}`}>
        <div className={`${isInsideFocusedUnit ? 'h-full bg-transparent' : 'bg-slate-900/20 rounded-[48px] border border-slate-800/40 p-6 md:p-12 shadow-2xl backdrop-blur-xl min-h-[500px]'}`}>

          {/* Top Level: Subjects */}
          {!selectedSubject && !isInsideFocusedUnit && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] flex items-center">
                  <i className="fas fa-cubes-stacked mr-4 text-indigo-500"></i> Subject Frameworks
                </h3>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
                {(activeCourse.subjects || []).map((subj) => (
                  <button 
                    key={subj.id} 
                    onClick={() => handleSubjectClick(subj)} 
                    className="flex flex-col p-10 bg-slate-950 border border-slate-800/60 rounded-[40px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-xl active:scale-98 text-left h-full"
                  >
                    <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-2xl border border-white/5 ${subj.color} group-hover:scale-110 transition-transform mb-8`}>
                      <i className={`fas ${subj.icon || 'fa-book'}`}></i>
                    </div>
                    <div className="space-y-2 flex-1">
                      <h4 className="text-2xl font-black text-slate-100 group-hover:text-white transition-colors tracking-tight">{subj.name}</h4>
                      <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">{subj.subSubjects.length} Core Paths</p>
