                    <div className="mt-10 pt-8 border-t border-slate-900/50 flex items-center justify-between text-[10px] font-black text-slate-500 group-hover:text-indigo-400 uppercase tracking-widest transition-colors">
                      <span>Enter Sequence</span>
                      <i className="fas fa-arrow-right-long group-hover:translate-x-2 transition-transform"></i>
                    </div>
                  </button>
                ))}
