          {/* SubSubject Level */}
          {selectedSubject && !selectedSubSubject && !isInsideFocusedUnit && (
            <div className="space-y-10 animate-in slide-in-from-right-8 duration-500">
               <div className="flex items-center space-x-6">
                <button onClick={handleBack} className="w-12 h-12 rounded-2xl bg-slate-950 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-xl group"><i className="fas fa-arrow-left group-hover:-translate-x-1 transition-transform"></i></button>
